{
  "name": "DesignTrack Pro",
  "description": "Uma aplicação completa para projetistas gerenciarem liberações, cronometrar tempo de projetos e reportar problemas de montagem, com insights via Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProjectType {
  VARIATION = 'Variação',
  DEVELOPMENT = 'Desenvolvimento',
  RELEASE = 'Liberação'
}

export enum IssueType {
  DESIGN_ERROR = 'Erro de Projeto',
  BENDING_ERROR = 'Erro de Dobra',
  CUTTING_ERROR = 'Erro de Corte',
  MATERIAL_ERROR = 'Erro de Material',
  ASSEMBLY_ERROR = 'Erro de Montagem'
}

export interface PauseRecord {
  reason: string;
  timestamp: string; // ISO string
  durationSeconds: number; // Approximate duration of this pause
}

export interface ProjectSession {
  id: string;
  ns: string;
  type: ProjectType;
  startTime: string; // ISO
  endTime?: string; // ISO
  totalActiveSeconds: number;
  pauses: PauseRecord[];
  status: 'COMPLETED' | 'IN_PROGRESS';
  notes?: string;
}

export interface IssueRecord {
  id: string;
  projectNs: string;
  type: IssueType;
  description: string;
  date: string;
}

export interface AppState {
  projects: ProjectSession[];
  issues: IssueRecord[];
}

import { ProjectType, IssueType } from './types';

export const PROJECT_TYPES = [
  ProjectType.RELEASE,
  ProjectType.VARIATION,
  ProjectType.DEVELOPMENT
];

export const ISSUE_TYPES = [
  IssueType.DESIGN_ERROR,
  IssueType.BENDING_ERROR,
  IssueType.CUTTING_ERROR,
  IssueType.MATERIAL_ERROR,
  IssueType.ASSEMBLY_ERROR
];

export const STORAGE_KEY = 'design_track_pro_data';

import { AppState, ProjectSession, IssueRecord } from '../types';
import { STORAGE_KEY } from '../constants';

const defaultState: AppState = {
  projects: [],
  issues: []
};

export const loadData = (): AppState => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : defaultState;
  } catch (error) {
    console.error("Failed to load data", error);
    return defaultState;
  }
};

export const saveData = (data: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch (error) {
    console.error("Failed to save data", error);
  }
};

export const addProject = (project: ProjectSession) => {
  const current = loadData();
  const updated = { ...current, projects: [project, ...current.projects] };
  saveData(updated);
  return updated;
};

export const addIssue = (issue: IssueRecord) => {
  const current = loadData();
  const updated = { ...current, issues: [issue, ...current.issues] };
  saveData(updated);
  return updated;
};

import { GoogleGenAI } from "@google/genai";
import { ProjectSession, IssueRecord } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzePerformance = async (projects: ProjectSession[], issues: IssueRecord[]) => {
  try {
    const projectSummary = projects.slice(0, 10).map(p => 
      `- NS: ${p.ns} (${p.type}): ${(p.totalActiveSeconds / 60).toFixed(1)} mins`
    ).join('\n');

    const issueSummary = issues.slice(0, 10).map(i => 
      `- ${i.type} em NS ${i.projectNs}: ${i.description}`
    ).join('\n');

    const prompt = `
      Analise os seguintes dados de desempenho de um projetista industrial.
      Forneça um resumo curto (máximo 3 parágrafos) em Português sobre eficiência e principais pontos de atenção.

      Projetos Recentes:
      ${projectSummary}

      Problemas Reportados Recentes:
      ${issueSummary}
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Fast response needed
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Não foi possível gerar a análise no momento. Verifique sua chave de API.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Square, Save, Clock, AlertCircle } from 'lucide-react';
import { ProjectType, ProjectSession, PauseRecord } from '../types';
import { PROJECT_TYPES } from '../constants';

interface ProjectTrackerProps {
  onSave: (project: ProjectSession) => void;
}

export const ProjectTracker: React.FC<ProjectTrackerProps> = ({ onSave }) => {
  const [status, setStatus] = useState<'IDLE' | 'RUNNING' | 'PAUSED'>('IDLE');

  // Form Data
  const [ns, setNs] = useState('');
  const [type, setType] = useState<ProjectType>(ProjectType.RELEASE);
  const [notes, setNotes] = useState('');

  // Timer Data
  const [startTime, setStartTime] = useState<string | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [pauses, setPauses] = useState<PauseRecord[]>([]);

  // Pause Logic
  const [showPauseModal, setShowPauseModal] = useState(false);
  const [pauseReason, setPauseReason] = useState('');
  const [tempPauseTime, setTempPauseTime] = useState<number | null>(null);

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (status === 'RUNNING') {
      timerRef.current = setInterval(() => {
        setElapsedSeconds(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status]);

  const handleStart = () => {
    if (!ns.trim()) {
      alert("Por favor, informe o NS do projeto antes de começar.");
      return;
    }
    setStartTime(new Date().toISOString());
    setStatus('RUNNING');
  };

  const initiatePause = () => {
    setStatus('PAUSED');
    setTempPauseTime(Date.now());
    setShowPauseModal(true);
  };

  const confirmPause = () => {
    if (!pauseReason.trim()) return;

    // We don't add the record yet, strictly speaking, we wait until resume to know duration?
    // Requirement says: "start counting... pause... resume". 
    // We will just store the state as PAUSED. The actual record creation happens on resume or finish usually, 
    // but here we just store the reason.

    // Actually, to track pause duration accurately:
    // When we click "Pause", the timer stops.
    // When we click "Resume", we calculate (Now - TempPauseTime) if we wanted 'wall clock' time.
    // But since `elapsedSeconds` is just active work time, we simply stop incrementing it.
    // We will just record that a pause happened.

    setShowPauseModal(false);
  };

  const handleResume = () => {
    const now = Date.now();
    const duration = tempPauseTime ? Math.floor((now - tempPauseTime) / 1000) : 0;

    setPauses(prev => [...prev, {
      reason: pauseReason,
      timestamp: new Date(tempPauseTime || now).toISOString(),
      durationSeconds: duration
    }]);

    setPauseReason('');
    setTempPauseTime(null);
    setStatus('RUNNING');
  };

  const handleFinish = () => {
    if (!startTime) return;

    const newProject: ProjectSession = {
      id: crypto.randomUUID(),
      ns,
      type,
      startTime,
      endTime: new Date().toISOString(),
      totalActiveSeconds: elapsedSeconds,
      pauses,
      status: 'COMPLETED',
      notes
    };

    onSave(newProject);
    resetForm();
  };

  const resetForm = () => {
    setStatus('IDLE');
    setNs('');
    setNotes('');
    setElapsedSeconds(0);
    setStartTime(null);
    setPauses([]);
    setPauseReason('');
    setShowPauseModal(false);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
      <h2 className="text-xl font-bold mb-4 flex items-center text-gray-800">
        <Clock className="w-6 h-6 mr-2 text-blue-600" />
        Rastreador de Liberação
      </h2>

      {status === 'IDLE' ? (
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">NS do Produto</label>
              <input 
                type="text" 
                value={ns}
                onChange={e => setNs(e.target.value)}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 123456"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Projeto</label>
              <select 
                value={type}
                onChange={e => setType(e.target.value as ProjectType)}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {PROJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <button 
            onClick={handleStart}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
          >
            <Play className="w-5 h-5 mr-2" />
            Começar Projeto
          </button>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="flex flex-col items-center justify-center bg-gray-50 p-6 rounded-xl border border-gray-200">
            <span className="text-sm text-gray-500 font-medium tracking-wider uppercase mb-1">{status === 'PAUSED' ? 'PROJETO PAUSADO' : 'EM ANDAMENTO'}</span>
            <div className={`text-6xl font-mono font-bold ${status === 'PAUSED' ? 'text-yellow-600' : 'text-blue-600'}`}>
              {formatTime(elapsedSeconds)}
            </div>
            <div className="text-gray-600 mt-2 font-medium">NS: {ns} • {type}</div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            {status === 'RUNNING' && (
              <button 
                onClick={initiatePause}
                className="bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
              >
                <Pause className="w-5 h-5 mr-2" />
                Pausar
              </button>
            )}

            {status === 'PAUSED' && (
               /* The actual resumption happens via the modal usually, but if they closed the modal without logic, we show a button here too or rely on modal logic */
               <button 
               onClick={() => setShowPauseModal(true)}
               className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
             >
               <Play className="w-5 h-5 mr-2" />
               Retomar
             </button>
            )}

            <button 
              onClick={handleFinish}
              disabled={status === 'PAUSED'} // Force resume before finish usually, or allow finish from pause. Let's disable while paused to ensure clarity.
              className={`font-bold py-3 rounded-lg flex items-center justify-center transition-colors text-white ${status === 'PAUSED' ? 'bg-gray-400 cursor-not-allowed' : 'bg-red-600 hover:bg-red-700'}`}
            >
              <Square className="w-5 h-5 mr-2 fill-current" />
              Finalizar
            </button>
          </div>
        </div>
      )}

      {/* Pause Modal */}
      {showPauseModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md mx-4">
            <h3 className="text-lg font-bold mb-4 flex items-center text-yellow-600">
              <AlertCircle className="w-5 h-5 mr-2" />
              Motivo da Pausa
            </h3>
            <p className="text-sm text-gray-600 mb-4">Por que você precisa parar o cronômetro?</p>
            <input 
              type="text" 
              autoFocus
              value={pauseReason}
              onChange={e => setPauseReason(e.target.value)}
              placeholder="Ex: Ir a fabrica, Reunião, Almoço..."
              className="w-full p-3 border rounded-lg mb-4 focus:ring-2 focus:ring-yellow-500 outline-none"
            />
            <div className="flex justify-end gap-2">
               {/* If currently running, we are confirming the pause. If currently paused, we are confirming the RESUME logic essentially? 
                   Actually simpler flow: 
                   1. Click Pause Button -> Status becomes PAUSED immediately? Or waiting for input?
                   Let's say Status BECOMES PAUSED immediately to stop timer. 
                   Then we ask for reason. When confirmed, we keep it paused.
                   To Resume, we click Resume, and maybe check if reason was filled?
               */}
               {status === 'PAUSED' && pauseReason ? (
                  <button 
                    onClick={handleResume}
                    className="bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700"
                  >
                    Salvar e Retomar
                  </button>
               ) : (
                 <button 
                   onClick={confirmPause}
                   disabled={!pauseReason}
                   className="bg-yellow-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-yellow-700 disabled:opacity-50"
                 >
                   Confirmar Pausa
                 </button>
               )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { AlertTriangle, Plus } from 'lucide-react';
import { IssueType, IssueRecord } from '../types';
import { ISSUE_TYPES } from '../constants';

interface IssueReporterProps {
  onReport: (issue: IssueRecord) => void;
}

export const IssueReporter: React.FC<IssueReporterProps> = ({ onReport }) => {
  const [ns, setNs] = useState('');
  const [type, setType] = useState<IssueType>(IssueType.ASSEMBLY_ERROR);
  const [description, setDescription] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!ns.trim() || !description.trim()) return;

    const newIssue: IssueRecord = {
      id: crypto.randomUUID(),
      projectNs: ns,
      type,
      description,
      date: new Date().toISOString()
    };

    onReport(newIssue);
    setNs('');
    setDescription('');
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
      <h2 className="text-xl font-bold mb-4 flex items-center text-red-600">
        <AlertTriangle className="w-6 h-6 mr-2" />
        Reportar Problema
      </h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">NS do Produto Afetado</label>
          <input 
            type="text" 
            value={ns}
            onChange={e => setNs(e.target.value)}
            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none"
            placeholder="Ex: 123456"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Erro</label>
          <select 
            value={type}
            onChange={e => setType(e.target.value as IssueType)}
            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none"
          >
            {ISSUE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Descrição Detalhada</label>
          <textarea 
            value={description}
            onChange={e => setDescription(e.target.value)}
            rows={3}
            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-red-500 outline-none"
            placeholder="Descreva o que aconteceu..."
            required
          />
        </div>

        <button 
          type="submit"
          className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-2 rounded-lg flex items-center justify-center transition-colors"
        >
          <Plus className="w-5 h-5 mr-2" />
          Registrar Problema
        </button>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { Sparkles, Activity } from 'lucide-react';
import { AppState } from '../types';
import { analyzePerformance } from '../services/geminiService';

interface DashboardProps {
  data: AppState;
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

export const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Prepare Data for Charts
  const projectsByType = data.projects.reduce((acc, curr) => {
    acc[curr.type] = (acc[curr.type] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const pieData = Object.keys(projectsByType).map(type => ({
    name: type,
    value: projectsByType[type]
  }));

  const issuesByType = data.issues.reduce((acc, curr) => {
    acc[curr.type] = (acc[curr.type] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const barData = Object.keys(issuesByType).map(type => ({
    name: type,
    count: issuesByType[type]
  }));

  const handleAiAnalysis = async () => {
    setIsLoadingAi(true);
    const result = await analyzePerformance(data.projects, data.issues);
    setAiAnalysis(result);
    setIsLoadingAi(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-6">
        {/* Project Type Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex-1 min-h-[300px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4">Liberações por Tipo</h3>
          <ResponsiveContainer width="100%" height={250}>
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Issue Frequency */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex-1 min-h-[300px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4">Frequência de Problemas</h3>
          <ResponsiveContainer width="100%" height={250}>
            <BarChart data={barData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" hide /> {/* Hide text if too long, rely on legend/tooltip */}
              <YAxis allowDecimals={false} />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" name="Ocorrências" fill="#ef4444" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* AI Insights Section */}
      <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-xl font-bold text-indigo-900 flex items-center">
            <Sparkles className="w-5 h-5 mr-2 text-indigo-600" />
            Análise Inteligente (IA)
          </h3>
          <button 
            onClick={handleAiAnalysis}
            disabled={isLoadingAi}
            className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-indigo-700 transition-colors disabled:opacity-50"
          >
            {isLoadingAi ? 'Analisando...' : 'Gerar Relatório'}
          </button>
        </div>

        {aiAnalysis ? (
          <div className="prose prose-sm max-w-none text-indigo-900 bg-white/50 p-4 rounded-lg">
            <pre className="whitespace-pre-wrap font-sans text-sm leading-relaxed">{aiAnalysis}</pre>
          </div>
        ) : (
          <p className="text-indigo-600/70 text-sm">
            Clique em "Gerar Relatório" para que a IA analise seus tempos de projeto e os erros reportados para sugerir melhorias.
          </p>
        )}
      </div>

      {/* Recent History Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-4 border-b border-gray-100 flex items-center">
          <Activity className="w-5 h-5 mr-2 text-gray-500" />
          <h3 className="font-bold text-gray-700">Histórico Recente</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-medium">
              <tr>
                <th className="p-4">Data</th>
                <th className="p-4">NS</th>
                <th className="p-4">Tipo</th>
                <th className="p-4">Duração</th>
                <th className="p-4">Pausas</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {data.projects.slice(0, 5).map(p => (
                <tr key={p.id} className="hover:bg-gray-50">
                  <td className="p-4 text-gray-600">{new Date(p.startTime).toLocaleDateString('pt-BR')}</td>
                  <td className="p-4 font-mono font-medium text-gray-800">{p.ns}</td>
                  <td className="p-4">
                    <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                      p.type === 'Variação' ? 'bg-blue-100 text-blue-800' :
                      p.type === 'Liberação' ? 'bg-green-100 text-green-800' :
                      'bg-purple-100 text-purple-800'
                    }`}>
                      {p.type}
                    </span>
                  </td>
                  <td className="p-4 font-mono text-gray-600">{(p.totalActiveSeconds / 60).toFixed(1)} min</td>
                  <td className="p-4 text-gray-500">{p.pauses.length}</td>
                </tr>
              ))}
              {data.projects.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-8 text-center text-gray-400">Nenhum projeto registrado ainda.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Timer, AlertOctagon, Menu, X } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { Dashboard } from './components/Dashboard';
import { loadData, addProject, addIssue } from './services/storageService';
import { AppState, ProjectSession, IssueRecord } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues'>('tracker');
  const [data, setData] = useState<AppState>({ projects: [], issues: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    setData(loadData());
  }, []);

  const handleProjectSave = (project: ProjectSession) => {
    const updated = addProject(project);
    setData(updated);
    // Optional: Switch to dashboard or stay? Staying is usually better for back-to-back work.
    alert(`Projeto NS ${project.ns} salvo com sucesso!`);
  };

  const handleIssueReport = (issue: IssueRecord) => {
    const updated = addIssue(issue);
    setData(updated);
    alert('Problema registrado com sucesso.');
  };

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
