import React, { useState, useMemo } from 'react';
import { Filter, Calendar, Search, Clock } from 'lucide-react';
import { AppState, ProjectType } from '../types';
import { PROJECT_TYPES } from '../constants';

interface ProjectHistoryProps {
  data: AppState;
}

export const ProjectHistory: React.FC<ProjectHistoryProps> = ({ data }) => {
  const [filterNs, setFilterNs] = useState('');
  const [filterType, setFilterType] = useState<string>('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const filteredProjects = useMemo(() => {
    return data.projects.filter(p => {
      const matchNs = p.ns.toLowerCase().includes(filterNs.toLowerCase());
      const matchType = filterType ? p.type === filterType : true;

      let matchDate = true;
      if (startDate || endDate) {
        const pDate = new Date(p.startTime).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        // End of the selected day
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = pDate >= start && pDate <= end;
      }

      return matchNs && matchType && matchDate;
    }).sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());
  }, [data.projects, filterNs, filterType, startDate, endDate]);

  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h ${m}m`;
  };

  const formatPauseDuration = (seconds: number) => {
     if (seconds < 60) return `${seconds}s`;
     const m = Math.floor(seconds / 60);
     return `${m}m`;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  return (
    <div className="space-y-6">
      {/* Filters Section */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <div className="flex items-center mb-4 text-gray-700 font-bold">
          <Filter className="w-5 h-5 mr-2 text-blue-600" />
          Filtros de Busca
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="relative">
            <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Buscar por NS..."
              value={filterNs}
              onChange={(e) => setFilterNs(e.target.value)}
              className="w-full pl-10 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>

          <select
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
            className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
          >
            <option value="">Todos os Tipos</option>
            {PROJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>

          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">De:</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>

          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">Até:</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>
        </div>
      </div>

      {/* Results Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-100">
              <tr>
                <th className="p-4">Status</th>
                <th className="p-4">NS</th>
                <th className="p-4">Tipo</th>
                <th className="p-4">Início</th>
                <th className="p-4">Fim</th>
                <th className="p-4">Duração Total</th>
                <th className="p-4">Motivos de Pausa</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredProjects.map((project) => (
                <tr key={project.id} className="hover:bg-gray-50 transition-colors">
                  <td className="p-4">
                    <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                      project.status === 'COMPLETED' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'
                    }`}>
                      {project.status === 'COMPLETED' ? 'Concluído' : 'Em Andamento'}
                    </span>
                  </td>
                  <td className="p-4 font-mono font-bold text-gray-800">{project.ns}</td>
                  <td className="p-4">
                     <span className={`px-2 py-1 rounded-full text-xs font-medium border ${
                      project.type === 'Variação' ? 'bg-indigo-50 border-indigo-100 text-indigo-700' :
                      project.type === 'Liberação' ? 'bg-emerald-50 border-emerald-100 text-emerald-700' :
                      'bg-amber-50 border-amber-100 text-amber-700'
                    }`}>
                      {project.type}
                    </span>
                  </td>
                  <td className="p-4 text-gray-600">{formatDate(project.startTime)}</td>
                  <td className="p-4 text-gray-600">{project.endTime ? formatDate(project.endTime) : '-'}</td>
                  <td className="p-4 font-medium text-gray-800 flex items-center">
                    <Clock className="w-4 h-4 mr-1 text-gray-400" />
                    {formatDuration(project.totalActiveSeconds)}
                  </td>
                  <td className="p-4 text-gray-500">
                    {project.pauses.length > 0 ? (
                      <div className="flex flex-col gap-1 max-w-[200px]">
                        {project.pauses.map((p, idx) => (
                           <div key={idx} className="text-xs bg-yellow-50 text-yellow-800 px-2 py-1 rounded border border-yellow-100 flex justify-between items-center">
                             <span className="truncate mr-2" title={p.reason}>{p.reason}</span>
                             <span className="font-mono text-yellow-600/70">{formatPauseDuration(p.durationSeconds)}</span>
                           </div>
                        ))}
                      </div>
                    ) : (
                      <span className="text-gray-300">-</span>
                    )}
                  </td>
                </tr>
              ))}
              {filteredProjects.length === 0 && (
                <tr>
                  <td colSpan={7} className="p-12 text-center text-gray-400">
                    Nenhum projeto encontrado com os filtros selecionados.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export enum ProjectType {
  VARIATION = 'Variação',
  DEVELOPMENT = 'Desenvolvimento',
  RELEASE = 'Liberação'
}

export enum IssueType {
  DESIGN_ERROR = 'Erro de Projeto',
  BENDING_ERROR = 'Erro de Dobra',
  CUTTING_ERROR = 'Erro de Corte',
  MATERIAL_ERROR = 'Erro de Material',
  ASSEMBLY_ERROR = 'Erro de Montagem'
}

export interface PauseRecord {
  reason: string;
  timestamp: string; // ISO string
  durationSeconds: number; // Approximate duration of this pause
}

export interface ProjectSession {
  id: string;
  ns: string;
  projectCode?: string; // New field
  type: ProjectType;
  startTime: string; // ISO
  endTime?: string; // ISO
  totalActiveSeconds: number;
  pauses: PauseRecord[];
  status: 'COMPLETED' | 'IN_PROGRESS';
  notes?: string;
}

export interface IssueRecord {
  id: string;
  projectNs: string;
  type: IssueType;
  description: string;
  date: string;
}

export interface AppState {
  projects: ProjectSession[];
  issues: IssueRecord[];
}

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Square, Clock, AlertCircle, Timer, Hash } from 'lucide-react';
import { ProjectType, ProjectSession, PauseRecord } from '../types';
import { PROJECT_TYPES } from '../constants';

// SUBSTITUA ISSO PELA SUA URL DO WEBHOOK DO TEAMS
// (Crie um no Teams: Canal -> Conectores -> Incoming Webhook)
const TEAMS_WEBHOOK_URL = "https://outlook.office.com/webhook/YOUR_WEBHOOK_URL_HERE";

interface ProjectTrackerProps {
  onSave: (project: ProjectSession) => void;
}

export const ProjectTracker: React.FC<ProjectTrackerProps> = ({ onSave }) => {
  const [status, setStatus] = useState<'IDLE' | 'RUNNING' | 'PAUSED'>('IDLE');

  // Form Data
  const [ns, setNs] = useState('');
  const [projectCode, setProjectCode] = useState('');
  const [type, setType] = useState<ProjectType>(ProjectType.RELEASE);
  const [notes, setNotes] = useState('');

  // Timer Data
  const [startTime, setStartTime] = useState<string | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [pauses, setPauses] = useState<PauseRecord[]>([]);

  // Pause Logic
  const [showPauseModal, setShowPauseModal] = useState(false);
  const [pauseReason, setPauseReason] = useState('');
  const [tempPauseTime, setTempPauseTime] = useState<number | null>(null);

  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (status === 'RUNNING') {
      timerRef.current = setInterval(() => {
        setElapsedSeconds(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status]);

  const handleStart = () => {
    if (!ns.trim()) {
      alert("Por favor, informe o NS do projeto antes de começar.");
      return;
    }
    setStartTime(new Date().toISOString());
    setStatus('RUNNING');
  };

  const initiatePause = () => {
    setStatus('PAUSED');
    setTempPauseTime(Date.now());
    // Immediate pause, no modal
  };

  const handleResume = () => {
    if (!pauseReason.trim()) return;

    const now = Date.now();
    const duration = tempPauseTime ? Math.floor((now - tempPauseTime) / 1000) : 0;

    setPauses(prev => [...prev, {
      reason: pauseReason,
      timestamp: new Date(tempPauseTime || now).toISOString(),
      durationSeconds: duration
    }]);

    setPauseReason('');
    setTempPauseTime(null);
    setShowPauseModal(false);
    setStatus('RUNNING');
  };

  const sendTeamsNotification = async (project: ProjectSession) => {
    // Basic validation to avoid sending if URL isn't set (or is the placeholder)
    if (!TEAMS_WEBHOOK_URL || TEAMS_WEBHOOK_URL.includes("YOUR_WEBHOOK_URL_HERE")) {
      console.warn("Teams Webhook URL not configured in code.");
      return;
    }

    const duration = formatTime(project.totalActiveSeconds);

    const message = {
      "@type": "MessageCard",
      "@context": "http://schema.org/extensions",
      "themeColor": "0076D7",
      "summary": "Projeto Finalizado",
      "sections": [{
        "activityTitle": "✅ Projeto Finalizado",
        "activitySubtitle": `DesignTrack Pro`,
        "facts": [
          { "name": "NS:", "value": project.ns },
          { "name": "Código:", "value": project.projectCode || "N/A" },
          { "name": "Tipo:", "value": project.type },
          { "name": "Duração:", "value": duration },
          { "name": "Pausas:", "value": `${project.pauses.length}` }
        ],
        "markdown": true
      }]
    };

    try {
      await fetch(TEAMS_WEBHOOK_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(message)
      });
      console.log("Notificação enviada para o Teams");
    } catch (error) {
      console.error("Erro ao enviar notificação para Teams (provável erro de CORS ou URL inválida):", error);
      // Note: Em alguns ambientes browser-only, Webhooks do Teams podem ser bloqueados por CORS. 
      // Se isso ocorrer, seria necessário um proxy, mas para teste local ou apps desktop via Electron funciona melhor.
    }
  };

  const handleFinish = async () => {
    if (!startTime) return;

    const newProject: ProjectSession = {
      id: crypto.randomUUID(),
      ns,
      projectCode,
      type,
      startTime,
      endTime: new Date().toISOString(),
      totalActiveSeconds: elapsedSeconds,
      pauses,
      status: 'COMPLETED',
      notes
    };

    // Save locally
    onSave(newProject);

    // Send to Teams (Fire and forget, don't await blocking UI)
    sendTeamsNotification(newProject);

    resetForm();
  };

  const resetForm = () => {
    setStatus('IDLE');
    setNs('');
    setProjectCode('');
    setNotes('');
    setElapsedSeconds(0);
    setStartTime(null);
    setPauses([]);
    setPauseReason('');
    setShowPauseModal(false);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
      <h2 className="text-xl font-bold mb-4 flex items-center text-gray-800">
        <Clock className="w-6 h-6 mr-2 text-blue-600" />
        Rastreador de Liberação
      </h2>

      {status === 'IDLE' ? (
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">NS do Produto</label>
              <input 
                type="text" 
                value={ns}
                onChange={e => setNs(e.target.value)}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 123456"
              />
            </div>
             <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Cód. Projeto</label>
              <div className="relative">
                <Hash className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                <input 
                  type="text" 
                  value={projectCode}
                  onChange={e => setProjectCode(e.target.value)}
                  className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Ex: PRJ-001"
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Projeto</label>
              <select 
                value={type}
                onChange={e => setType(e.target.value as ProjectType)}
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {PROJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <button 
            onClick={handleStart}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
          >
            <Play className="w-5 h-5 mr-2" />
            Começar Projeto
          </button>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="flex flex-col items-center justify-center bg-gray-50 p-6 rounded-xl border border-gray-200">
            <span className="text-sm text-gray-500 font-medium tracking-wider uppercase mb-1">{status === 'PAUSED' ? 'PROJETO PAUSADO' : 'EM ANDAMENTO'}</span>
            <div className={`text-6xl font-mono font-bold ${status === 'PAUSED' ? 'text-yellow-600' : 'text-blue-600'}`}>
              {formatTime(elapsedSeconds)}
            </div>
            <div className="text-gray-600 mt-2 font-medium flex gap-2">
              <span>NS: {ns}</span>
              {projectCode && <span className="text-gray-400">• Cód: {projectCode}</span>}
              <span className="text-gray-400">• {type}</span>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            {status === 'RUNNING' && (
              <button 
                onClick={initiatePause}
                className="bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
              >
                <Pause className="w-5 h-5 mr-2" />
                Pausar
              </button>
            )}

            {status === 'PAUSED' && (
               <button 
               onClick={() => setShowPauseModal(true)}
               className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
             >
               <Play className="w-5 h-5 mr-2" />
               Retomar
             </button>
            )}

            <button 
              onClick={handleFinish}
              disabled={status === 'PAUSED'}
              className={`font-bold py-3 rounded-lg flex items-center justify-center transition-colors text-white ${status === 'PAUSED' ? 'bg-gray-400 cursor-not-allowed' : 'bg-red-600 hover:bg-red-700'}`}
            >
              <Square className="w-5 h-5 mr-2 fill-current" />
              Finalizar
            </button>
          </div>
        </div>
      )}

      {/* Resume Modal */}
      {showPauseModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200">
            <h3 className="text-lg font-bold mb-4 flex items-center text-blue-600">
              <Play className="w-5 h-5 mr-2" />
              Retomar Projeto
            </h3>

            <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 mb-4 flex items-center justify-between">
              <div className="flex items-center text-blue-800">
                <Timer className="w-4 h-4 mr-2" />
                <span className="text-sm font-medium">Tempo Trabalhado:</span>
              </div>
              <span className="text-xl font-mono font-bold text-blue-700">
                {formatTime(elapsedSeconds)}
              </span>
            </div>

            <p className="text-sm text-gray-600 mb-2">Informe o motivo da pausa para continuar:</p>
            <input 
              type="text" 
              autoFocus
              value={pauseReason}
              onChange={e => setPauseReason(e.target.value)}
              placeholder="Ex: Ir a fabrica, Reunião, Almoço..."
              className="w-full p-3 border rounded-lg mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
            />

            <div className="flex justify-end gap-2">
              <button 
                onClick={() => setShowPauseModal(false)}
                className="text-gray-500 px-4 py-2 rounded-lg font-medium hover:bg-gray-100"
              >
                Cancelar
              </button>
              <button 
                onClick={handleResume}
                disabled={!pauseReason.trim()}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700 disabled:opacity-50"
              >
                Salvar e Retomar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Filter, Calendar, Search, Clock, Hash } from 'lucide-react';
