interface DashboardProps {
  data: AppState;
}

const COLORS = ['#ef4444', '#f97316', '#eab308', '#3b82f6', '#8b5cf6'];

export const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // 1. Calculate Average Time per Project Type
  const averageTimes = useMemo(() => {
    const sums: Record<string, { total: number; count: number }> = {};

    data.projects.forEach(p => {
      if (p.status === 'COMPLETED') {
        if (!sums[p.type]) sums[p.type] = { total: 0, count: 0 };
        sums[p.type].total += p.totalActiveSeconds;
        sums[p.type].count += 1;
      }
    });

    return Object.entries(sums).map(([type, stats]) => ({
      type,
      avgSeconds: Math.round(stats.total / stats.count)
    }));
  }, [data.projects]);

  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h ${m}m`;
  };

  // 2. Bar Chart Data: Releases per Month
  const releasesByMonth = data.projects
    .filter(p => p.status === 'COMPLETED' && p.endTime)
    .reduce((acc, curr) => {
      const date = new Date(curr.endTime!);
      const monthYear = date.toLocaleString('pt-BR', { month: 'short' });
      const key = monthYear.charAt(0).toUpperCase() + monthYear.slice(1);
      acc[key] = (acc[key] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

  const barData = Object.keys(releasesByMonth).map(key => ({
    name: key,
    liberacoes: releasesByMonth[key]
  }));

  // 3. Pie Chart Data: Issue Type Distribution
  const issuesByType = data.issues.reduce((acc, curr) => {
    acc[curr.type] = (acc[curr.type] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const pieData = Object.keys(issuesByType).map(type => ({
    name: type,
    value: issuesByType[type]
  }));

  const handleAiAnalysis = async () => {
    setIsLoadingAi(true);
    const result = await analyzePerformance(data.projects, data.issues);
    setAiAnalysis(result);
    setIsLoadingAi(false);
  };

  const handleExportCSV = () => {
    const headers = ['ID', 'NS', 'Codigo', 'Tipo', 'Inicio', 'Fim', 'Tempo Total(s)', 'Status', 'Notas'];
    const rows = data.projects.map(p => [
      p.id,
      p.ns,
      p.projectCode || '',
      p.type,
      p.startTime,
      p.endTime || '',
      p.totalActiveSeconds,
      p.status,
      `"${(p.notes || '').replace(/"/g, '""')}"`
    ].join(','));

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `design_track_export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {averageTimes.length > 0 ? averageTimes.map((stat) => (
          <div key={stat.type} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Média {stat.type}</p>
              <p className="text-2xl font-bold text-gray-800">{formatDuration(stat.avgSeconds)}</p>
            </div>
            <div className="h-10 w-10 bg-blue-50 rounded-full flex items-center justify-center text-blue-600">
              <Clock className="w-5 h-5" />
            </div>
          </div>
        )) : (
          <div className="col-span-3 bg-white p-4 rounded-xl border border-gray-100 text-center text-gray-400 text-sm">
            Complete projetos para ver as médias de tempo por tipo.
          </div>
        )}
      </div>

      <div className="flex justify-end">
        <button 
          onClick={handleExportCSV}
