export enum ProjectType {
  VARIATION = 'Variação',
  DEVELOPMENT = 'Desenvolvimento',
  RELEASE = 'Liberação'
}

export enum IssueType {
  DESIGN_ERROR = 'Erro de Projeto',
  BENDING_ERROR = 'Erro de Dobra',
  CUTTING_ERROR = 'Erro de Corte',
  MATERIAL_ERROR = 'Erro de Material',
  ASSEMBLY_ERROR = 'Erro de Montagem'
}

export type UserRole = 'GESTOR' | 'PROJETISTA';

export interface User {
  id: string;
  username: string;
  password: string; // In a real app, this should be hashed. Storing plain for local prototype.
  name: string;
  role: UserRole;
}

export interface PauseRecord {
  reason: string;
  timestamp: string; // ISO string
  durationSeconds: number; // Approximate duration of this pause
}

export interface ProjectSession {
  id: string;
  ns: string;
  projectCode?: string; // New field
  type: ProjectType;
  startTime: string; // ISO
  endTime?: string; // ISO
  totalActiveSeconds: number;
  pauses: PauseRecord[];
  status: 'COMPLETED' | 'IN_PROGRESS';
  notes?: string;
  userId?: string; // Track who did this project
}

export interface IssueRecord {
  id: string;
  projectNs: string;
  type: IssueType;
  description: string;
  date: string;
  reportedBy?: string; // Track who reported
}

export interface AppState {
  projects: ProjectSession[];
  issues: IssueRecord[];
}

import { AppState, ProjectSession, IssueRecord, User } from '../types';
import { STORAGE_KEY } from '../constants';

const USERS_STORAGE_KEY = 'design_track_pro_users';

const defaultState: AppState = {
  projects: [],
  issues: []
};

// --- DATA MANAGEMENT ---

export const loadData = (): AppState => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : defaultState;
  } catch (error) {
    console.error("Failed to load data", error);
    return defaultState;
  }
};

export const saveData = (data: AppState) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch (error) {
    console.error("Failed to save data", error);
  }
};

export const addProject = (project: ProjectSession) => {
  const current = loadData();
  const updated = { ...current, projects: [project, ...current.projects] };
  saveData(updated);
  return updated;
};

export const addIssue = (issue: IssueRecord) => {
  const current = loadData();
  const updated = { ...current, issues: [issue, ...current.issues] };
  saveData(updated);
  return updated;
};

// --- USER MANAGEMENT ---

export const loadUsers = (): User[] => {
  try {
    const data = localStorage.getItem(USERS_STORAGE_KEY);
    if (!data) {
      // Seed default admin if no users exist
      const defaultAdmin: User = {
        id: 'admin-001',
        username: 'admin',
        password: '123456',
        name: 'Gestor Padrão',
        role: 'GESTOR'
      };
      saveUsers([defaultAdmin]);
      return [defaultAdmin];
    }
    return JSON.parse(data);
  } catch (error) {
    return [];
  }
};

export const saveUsers = (users: User[]) => {
  localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
};

export const registerUser = (user: User): boolean => {
  const users = loadUsers();
  if (users.find(u => u.username === user.username)) {
    return false; // User already exists
  }
  const updatedUsers = [...users, user];
  saveUsers(updatedUsers);
  return true;
};

export const authenticateUser = (username: string, password: string): User | null => {
  const users = loadUsers();
  const user = users.find(u => u.username === username && u.password === password);
  return user || null;
};

