import React, { useState, useMemo, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { Sparkles, BarChart3, PieChart as PieIcon, Download, Clock, Filter, Truck, User as UserIcon, Lightbulb, TrendingDown } from 'lucide-react';
import { AppState, User, InnovationType } from '../types';
import { analyzePerformance } from '../services/geminiService';
import { fetchUsers } from '../services/storageService';

interface DashboardProps {
  data: AppState;
  currentUser: User;
}

const COLORS = ['#ef4444', '#f97316', '#eab308', '#3b82f6', '#8b5cf6', '#ec4899'];

export const Dashboard: React.FC<DashboardProps> = ({ data, currentUser }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);
  const [usersMap, setUsersMap] = useState<Record<string, string>>({});

  // Filter States
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  useEffect(() => {
    // Load users for the manager chart
    const load = async () => {
      const users = await fetchUsers();
      const map = users.reduce((acc, u) => ({ ...acc, [u.id]: u.name }), {} as Record<string, string>);
      setUsersMap(map);
    };
    load();
  }, []);

  // Filter Data Logic
  const filteredProjects = useMemo(() => {
    return data.projects.filter(p => {
      if (p.status !== 'COMPLETED') return false;

      let matchDate = true;
      if (startDate || endDate) {
        const pDate = new Date(p.endTime || p.startTime).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = pDate >= start && pDate <= end;
      }
      return matchDate;
    });
  }, [data.projects, startDate, endDate]);

  const filteredIssues = useMemo(() => {
     return data.issues.filter(i => {
      let matchDate = true;
      if (startDate || endDate) {
        const iDate = new Date(i.date).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = iDate >= start && iDate <= end;
      }
      return matchDate;
     });
  }, [data.issues, startDate, endDate]);

   const filteredInnovations = useMemo(() => {
    return data.innovations.filter(inv => {
      let matchDate = true;
      if (startDate || endDate) {
        const iDate = new Date(inv.createdAt).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = iDate >= start && iDate <= end;
      }
      return matchDate;
    });
  }, [data.innovations, startDate, endDate]);


  // 1. Calculate Average Time per Project Type
  const averageTimes = useMemo(() => {
    const sums: Record<string, { total: number; count: number }> = {};

    filteredProjects.forEach(p => {
      if (!sums[p.type]) sums[p.type] = { total: 0, count: 0 };
      sums[p.type].total += p.totalActiveSeconds;
      sums[p.type].count += 1;
    });

    return Object.entries(sums).map(([type, stats]) => ({
      type,
      avgSeconds: Math.round(stats.total / stats.count)
    }));
  }, [filteredProjects]);

  // 1.5 Calculate Total Savings
  const totalSavings = useMemo(() => {
    return filteredInnovations.reduce((acc, curr) => {
        if(curr.costDifference > 0) return acc + curr.costDifference;
        return acc;
    }, 0);
  }, [filteredInnovations]);

  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h ${m}m`;
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  // 2. Bar Chart Data: Releases per Month
  const barData = useMemo(() => {
    const releasesByMonth = filteredProjects
      .reduce((acc, curr) => {
        const date = new Date(curr.endTime!);
        const monthYear = date.toLocaleString('pt-BR', { month: 'short' });
        const key = monthYear.charAt(0).toUpperCase() + monthYear.slice(1);
        acc[key] = (acc[key] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);

    return Object.keys(releasesByMonth).map(key => ({
      name: key,
      liberacoes: releasesByMonth[key]
    }));
  }, [filteredProjects]);

  // 3. Pie Chart Data: Issue Type Distribution
  const pieData = useMemo(() => {
    const issuesByType = filteredIssues.reduce((acc, curr) => {
      acc[curr.type] = (acc[curr.type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(issuesByType).map(type => ({
      name: type,
      value: issuesByType[type]
    }));
  }, [filteredIssues]);

  // 4. Pie Chart: Implement Type Distribution
  const implementData = useMemo(() => {
    const counts = filteredProjects.reduce((acc, curr) => {
      const type = curr.implementType || 'Não Informado';
      acc[type] = (acc[type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(counts).map(key => ({
      name: key,
      value: counts[key]
    }));
  }, [filteredProjects]);

  // 5. Bar Chart: Releases by Designer (Manager Only)
  const designerData = useMemo(() => {
    if (currentUser.role !== 'GESTOR') return [];

    const counts = filteredProjects.reduce((acc, curr) => {
      const name = usersMap[curr.userId || ''] || 'Desconhecido';
      acc[name] = (acc[name] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(counts).map(key => ({
      name: key,
      liberacoes: counts[key]
    }));
  }, [filteredProjects, currentUser.role, usersMap]);

  // 6. Stacked Bar Chart: Innovations by Status and Type
  const innovationChartData = useMemo(() => {
    const statuses = ['PENDING', 'APPROVED', 'IMPLEMENTED', 'REJECTED'];
    const labelMap: Record<string, string> = {
        'PENDING': 'Pendente',
        'APPROVED': 'Aprovado',
        'IMPLEMENTED': 'Implementado',
        'REJECTED': 'Rejeitado'
    };

    return statuses.map(status => {
        const items = filteredInnovations.filter(i => i.status === status);
        const newProjects = items.filter(i => i.type === InnovationType.NEW_PROJECT).length;
        const improvements = items.filter(i => i.type === InnovationType.PRODUCT_IMPROVEMENT).length;

        return {
            name: labelMap[status],
            "Novo Projeto": newProjects,
            "Melhoria": improvements
        };
    });
  }, [filteredInnovations]);


  const handleAiAnalysis = async () => {
    setIsLoadingAi(true);
    const result = await analyzePerformance(filteredProjects, filteredIssues);
    setAiAnalysis(result);
    setIsLoadingAi(false);
  };

  const handleExportCSV = () => {
    const headers = ['ID', 'NS', 'Codigo', 'Tipo', 'Implemento', 'Inicio', 'Fim', 'Tempo Total(s)', 'Status', 'Notas'];
    const rows = filteredProjects.map(p => [
      p.id,
      p.ns,
      p.projectCode || '',
      p.type,
      p.implementType || '',
      p.startTime,
      p.endTime || '',
      p.totalActiveSeconds,
      p.status,
      `"${(p.notes || '').replace(/"/g, '""')}"`
    ].join(','));

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `design_track_export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">

      {/* Date Filter Section */}
      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center text-gray-700 font-bold">
          <Filter className="w-5 h-5 mr-2 text-blue-600" />
          Período de Análise
        </div>
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">De:</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">Até:</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>
        </div>
        <button 
          onClick={handleExportCSV}
          className="flex items-center text-sm font-medium text-gray-600 hover:text-gray-900 bg-gray-50 border border-gray-200 px-4 py-2 rounded-lg hover:bg-gray-100 transition-colors ml-auto md:ml-0"
        >
          <Download className="w-4 h-4 mr-2" />
          CSV
        </button>
      </div>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {averageTimes.length > 0 && averageTimes.map((stat) => (
          <div key={stat.type} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Média {stat.type}</p>
              <p className="text-xl font-bold text-gray-800">{formatDuration(stat.avgSeconds)}</p>
            </div>
            <div className="h-8 w-8 bg-blue-50 rounded-full flex items-center justify-center text-blue-600">
              <Clock className="w-4 h-4" />
            </div>
          </div>
        ))}
        {/* Innovation KPI */}
         <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-xs font-bold text-emerald-600 uppercase tracking-wider mb-1">Economia Total</p>
              <p className="text-xl font-bold text-emerald-800">{formatCurrency(totalSavings)}</p>
            </div>
            <div className="h-8 w-8 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-600">
              <TrendingDown className="w-4 h-4" />
            </div>
          </div>
      </div>

      {/* AI Insights Section */}
      <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-xl font-bold text-indigo-900 flex items-center">
            <Sparkles className="w-5 h-5 mr-2 text-indigo-600" />
            Análise Inteligente (IA)
          </h3>
          <button 
            onClick={handleAiAnalysis}
            disabled={isLoadingAi}
            className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-indigo-700 transition-colors disabled:opacity-50"
          >
            {isLoadingAi ? 'Analisando...' : 'Gerar Relatório'}
          </button>
        </div>

        {aiAnalysis ? (
          <div className="prose prose-sm max-w-none text-indigo-900 bg-white/50 p-4 rounded-lg">
            <pre className="whitespace-pre-wrap font-sans text-sm leading-relaxed">{aiAnalysis}</pre>
          </div>
        ) : (
          <p className="text-indigo-600/70 text-sm">
            Clique em "Gerar Relatório" para que a IA analise o desempenho do período selecionado.
          </p>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Releases per Month (Bar Chart) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
            <BarChart3 className="w-5 h-5 mr-2 text-blue-500" />
            Liberações por Mês
          </h3>
          <div className="h-[250px] w-full">
            {barData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={barData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" tickLine={false} axisLine={false} />
                  <YAxis allowDecimals={false} tickLine={false} axisLine={false} />
                  <Tooltip cursor={{ fill: '#f3f4f6' }} />
                  <Bar dataKey="liberacoes" name="Liberações" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                Sem dados para exibir.
              </div>
            )}
          </div>
        </div>

        {/* Innovations Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
            <Lightbulb className="w-5 h-5 mr-2 text-yellow-500" />
            Status de Inovações
          </h3>
           <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={innovationChartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" tickLine={false} axisLine={false} style={{fontSize: '12px'}} />
                    <YAxis allowDecimals={false} tickLine={false} axisLine={false} />
                    <Tooltip cursor={{ fill: '#f3f4f6' }} />
                    <Legend />
                    <Bar dataKey="Novo Projeto" stackId="a" fill="#8b5cf6" />
                    <Bar dataKey="Melhoria" stackId="a" fill="#3b82f6" />
                </BarChart>
            </ResponsiveContainer>
           </div>
        </div>

        {/* Implement Type (Pie Chart) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
            <Truck className="w-5 h-5 mr-2 text-orange-500" />
            Distribuição por Implemento
          </h3>
          <div className="h-[250px] w-full">
            {implementData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={implementData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    outerRadius={80}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {implementData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend 
                    layout="vertical" 
                    verticalAlign="middle" 
                    align="right"
                    wrapperStyle={{ fontSize: '12px' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                Sem dados para exibir.
              </div>
            )}
          </div>
        </div>

        {/* Issue Distribution (Pie Chart) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
          <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
            <PieIcon className="w-5 h-5 mr-2 text-red-500" />
            Distribuição de Problemas
          </h3>
          <div className="h-[250px] w-full">
            {pieData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    outerRadius={80}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {pieData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend 
                    layout="vertical" 
                    verticalAlign="middle" 
                    align="right"
                    wrapperStyle={{ fontSize: '12px' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                Nenhum problema registrado no período.
              </div>
            )}
          </div>
        </div>

        {/* Manager Only: Releases by Designer */}
        {currentUser.role === 'GESTOR' && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
            <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
              <UserIcon className="w-5 h-5 mr-2 text-purple-600" />
              Liberações por Projetista
            </h3>
             <div className="h-[250px] w-full">
              {designerData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={designerData} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                    <XAxis type="number" allowDecimals={false} tickLine={false} axisLine={false} />
                    <YAxis dataKey="name" type="category" width={100} tickLine={false} axisLine={false} />
                    <Tooltip cursor={{ fill: '#f3f4f6' }} />
                    <Bar dataKey="liberacoes" name="Projetos" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                  Sem dados para exibir.
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Lightbulb, Plus, TrendingDown, TrendingUp, DollarSign, Calendar, User as UserIcon, Check, X, PlayCircle } from 'lucide-react';
import { InnovationType, InnovationRecord, User, AppState } from '../types';
import { fetchUsers } from '../services/storageService';

interface InnovationManagerProps {
  innovations: InnovationRecord[];
  onAdd: (innovation: InnovationRecord) => void;
  onStatusChange: (id: string, status: string) => void;
  currentUser: User;
}

export const InnovationManager: React.FC<InnovationManagerProps> = ({ innovations, onAdd, onStatusChange, currentUser }) => {
  const [showForm, setShowForm] = useState(false);
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [type, setType] = useState<InnovationType>(InnovationType.PRODUCT_IMPROVEMENT);
  const [currentCost, setCurrentCost] = useState<string>('');
  const [projectedCost, setProjectedCost] = useState<string>('');
  const [usersMap, setUsersMap] = useState<Record<string, string>>({});

  useEffect(() => {
    const load = async () => {
      const users = await fetchUsers();
      const map = users.reduce((acc, u) => ({ ...acc, [u.id]: u.name }), {} as Record<string, string>);
      setUsersMap(map);
    };
    load();
  }, []);

  // Sort innovations by date descending
  const sortedInnovations = useMemo(() => {
    return [...innovations].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [innovations]);

  // Calculate totals
  const totalSavings = useMemo(() => {
    return innovations.reduce((acc, curr) => {
      // If difference is positive, it's a saving
      // Consider counting only APPROVED or IMPLEMENTED? For now, all.
      if (curr.costDifference > 0) return acc + curr.costDifference;
      return acc;
    }, 0);
  }, [innovations]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const curr = parseFloat(currentCost) || 0;
    const proj = parseFloat(projectedCost) || 0;

    // Logic: If Improvement: Savings = Current - Projected
    // Logic: If New Project: "Difference" might represent margin or saving vs competitor, 
    // but here we simply assume User inputs "Current" as baseline/0 if it's completely new.
    const difference = curr - proj;

    const newRecord: InnovationRecord = {
      id: crypto.randomUUID(),
      title,
      description,
      type,
      currentCost: curr,
      projectedCost: proj,
      costDifference: difference,
      status: 'PENDING',
      authorId: currentUser.id,
      createdAt: new Date().toISOString()
    };

    onAdd(newRecord);

    // Reset form
    setTitle('');
    setDescription('');
    setCurrentCost('');
    setProjectedCost('');
    setShowForm(false);
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const getStatusColor = (status: string) => {
      switch(status) {
          case 'APPROVED': return 'bg-blue-100 text-blue-700';
          case 'IMPLEMENTED': return 'bg-green-100 text-green-700';
          case 'REJECTED': return 'bg-red-100 text-red-700';
          default: return 'bg-gray-100 text-gray-700';
      }
  }

  const getStatusLabel = (status: string) => {
      switch(status) {
          case 'APPROVED': return 'Aprovado';
          case 'IMPLEMENTED': return 'Implementado';
          case 'REJECTED': return 'Rejeitado';
          default: return 'Pendente';
      }
  }

  return (
    <div className="space-y-6">
      {/* Header & Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center">
            <Lightbulb className="w-6 h-6 mr-2 text-yellow-500" />
            Inovações e Custos
          </h2>
          <p className="text-gray-500 mt-1">Gerencie novas ideias e reduções de custo.</p>
        </div>

        <div className="bg-gradient-to-r from-emerald-500 to-teal-600 rounded-xl p-6 text-white shadow-lg">
          <div className="text-emerald-100 text-sm font-medium mb-1 uppercase tracking-wider">Economia Total Projetada</div>
          <div className="text-4xl font-bold font-mono">{formatCurrency(totalSavings)}</div>
          <div className="text-emerald-100 text-xs mt-2 flex items-center">
            <TrendingDown className="w-4 h-4 mr-1" />
            Baseado em melhorias cadastradas
          </div>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex justify-end">
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-lg flex items-center transition-colors shadow-sm"
        >
          <Plus className="w-5 h-5 mr-2" />
          Nova Ideia / Melhoria
        </button>
      </div>

      {/* Form */}
      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold text-lg mb-4 text-gray-700">Registrar Inovação</h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-700 mb-1">Título do Projeto</label>
                <input 
                  type="text" 
                  value={title}
                  onChange={e => setTitle(e.target.value)}
                  className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Ex: Novo sistema de fixação..."
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tipo</label>
                <select 
                  value={type}
                  onChange={e => setType(e.target.value as InnovationType)}
                  className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  <option value={InnovationType.PRODUCT_IMPROVEMENT}>Melhoria de Produto</option>
                  <option value={InnovationType.NEW_PROJECT}>Novo Projeto</option>
                </select>
              </div>

              <div>
                {/* Spacer or additional field */}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Custo Atual (R$)</label>
                <div className="relative">
                   <DollarSign className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                   <input 
                    type="number" 
                    step="0.01"
                    value={currentCost}
                    onChange={e => setCurrentCost(e.target.value)}
                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    placeholder="0.00"
                  />
                </div>
                <p className="text-xs text-gray-400 mt-1">Deixe 0 se for projeto totalmente novo.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Custo Projetado (R$)</label>
                 <div className="relative">
                   <DollarSign className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                   <input 
                    type="number" 
                    step="0.01"
                    value={projectedCost}
                    onChange={e => setProjectedCost(e.target.value)}
                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    placeholder="0.00"
                    required
                  />
                </div>
              </div>

              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-700 mb-1">Descrição / Detalhes</label>
                <textarea 
                  value={description}
                  onChange={e => setDescription(e.target.value)}
                  rows={3}
                  className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Descreva as mudanças e o impacto esperado..."
                  required
                />
              </div>
            </div>

            <div className="flex justify-end gap-2 pt-2">
               <button 
                  type="button"
                  onClick={() => setShowForm(false)}
                  className="px-4 py-2 text-gray-500 hover:bg-gray-100 rounded-lg transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-6 rounded-lg transition-colors"
                >
                  Salvar
                </button>
            </div>
          </form>
        </div>
      )}

      {/* List */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-sm text-left">
          <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-100">
            <tr>
              <th className="p-4">Projeto / Inovação</th>
              <th className="p-4">Tipo</th>
              <th className="p-4">Status</th>
              <th className="p-4">Novo Custo</th>
              <th className="p-4 text-right">Impacto</th>
              {currentUser.role === 'GESTOR' && <th className="p-4 text-right">Ações</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {sortedInnovations.map((inv) => (
              <tr key={inv.id} className="hover:bg-gray-50 transition-colors">
                <td className="p-4">
                  <div className="font-bold text-gray-800">{inv.title}</div>
                  <div className="text-xs text-gray-500 mt-1 line-clamp-1">{inv.description}</div>
                  <div className="flex items-center gap-2 mt-2 text-xs text-gray-400">
                    <span className="flex items-center"><Calendar className="w-3 h-3 mr-1"/> {new Date(inv.createdAt).toLocaleDateString()}</span>
                    {inv.authorId && (
                      <span className="flex items-center"><UserIcon className="w-3 h-3 mr-1"/> {usersMap[inv.authorId] || '...'}</span>
                    )}
                  </div>
                </td>
                <td className="p-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                    inv.type === InnovationType.NEW_PROJECT 
                    ? 'bg-purple-100 text-purple-700' 
                    : 'bg-blue-100 text-blue-700'
                  }`}>
                    {inv.type}
                  </span>
                </td>
                <td className="p-4">
                   <span className={`px-2 py-1 rounded text-xs font-bold uppercase tracking-wide ${getStatusColor(inv.status)}`}>
                       {getStatusLabel(inv.status)}
                   </span>
                </td>
                <td className="p-4 font-medium text-gray-700">
                  {formatCurrency(inv.projectedCost)}
                </td>
                <td className="p-4 text-right">
                  <div className={`flex items-center justify-end font-bold ${
                    inv.costDifference > 0 ? 'text-green-600' : 
                    inv.costDifference < 0 ? 'text-red-600' : 'text-gray-500'
                  }`}>
                    {inv.costDifference > 0 ? (
                      <>
                        <TrendingDown className="w-4 h-4 mr-1" />
                        {formatCurrency(inv.costDifference)}
                      </>
                    ) : inv.costDifference < 0 ? (
                      <>
                        <TrendingUp className="w-4 h-4 mr-1" />
                        {formatCurrency(Math.abs(inv.costDifference))}
                      </>
                    ) : (
                      <span>-</span>
                    )}
                  </div>
                </td>
                {currentUser.role === 'GESTOR' && (
                    <td className="p-4 text-right">
                        {inv.status === 'PENDING' && (
                            <div className="flex justify-end gap-1">
                                <button 
                                    onClick={() => onStatusChange(inv.id, 'APPROVED')}
                                    title="Aprovar"
                                    className="p-1.5 bg-green-50 text-green-600 rounded hover:bg-green-100 transition"
                                >
                                    <Check className="w-4 h-4" />
                                </button>
                                <button 
                                    onClick={() => onStatusChange(inv.id, 'REJECTED')}
                                    title="Rejeitar"
                                    className="p-1.5 bg-red-50 text-red-600 rounded hover:bg-red-100 transition"
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            </div>
                        )}
                        {inv.status === 'APPROVED' && (
                             <button 
                                onClick={() => onStatusChange(inv.id, 'IMPLEMENTED')}
                                className="text-xs bg-blue-600 text-white px-3 py-1 rounded hover:bg-blue-700 transition flex items-center ml-auto"
                            >
                                <PlayCircle className="w-3 h-3 mr-1" />
                                Implementar
                            </button>
                        )}
                    </td>
                )}
              </tr>
            ))}
            {sortedInnovations.length === 0 && (
              <tr>
                <td colSpan={6} className="p-8 text-center text-gray-400">
                  Nenhuma inovação registrada ainda.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PenTool, AlertOctagon, Menu, X, History, Users, LogOut, Lightbulb } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { IssueHistory } from './components/IssueHistory';
import { Dashboard } from './components/Dashboard';
import { ProjectHistory } from './components/ProjectHistory';
import { UserManagement } from './components/UserManagement';
import { InnovationManager } from './components/InnovationManager';
import { Login } from './components/Login';
import { fetchAppState, addProject, addIssue, addInnovation, updateInnovationStatus } from './services/storageService';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from './types';

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); // Reload if user changes (or initial load)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    // GESTOR sees everything
    if (currentUser.role === 'GESTOR') {
      return data;
    }

    // PROJETISTA sees only their own items (mostly), but might see shared Innovations
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      // For innovations, usually it's good for everyone to see, but editing is restricted. 
      // For simplicity here, we show all so they can see colleagues' ideas, or filter if preferred.
      // Let's show all innovations for collaboration.
      innovations: data.innovations
    };
  }, [data, currentUser]);

  const handleProjectSave = async (project: ProjectSession) => {
    setIsLoading(true);
    // Inject current user ID into project
    const projectWithUser = { ...project, userId: currentUser?.id };

    // Optimistic update
    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));

    // Async save to DB and refresh
    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
      alert(`Projeto NS ${project.ns} salvo com sucesso!`);
    } catch (e) {
      alert("Erro ao salvar no banco de dados.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    // Inject current user ID into issue
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };

     // Optimistic update
     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));

    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    // Optimistic update
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));

    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      alert("Erro ao salvar inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  }

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors ${
        activeTab === id 
          ? 'bg-slate-800 border-r-4 border-blue-500 text-blue-400 font-medium' 
          : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white">
        <div className="p-6 border-b border-slate-800">
          {/* Logo Placeholder */}
          <div className="mb-4">
             <img 
               src="https://placehold.co/150x50/transparent/white?text=LOGO" 
               alt="Logo da Empresa" 
               className="h-10 w-auto object-contain" 
             />
          </div>

          <div className="flex items-center text-slate-400 text-xs mb-1">
            <span className="font-semibold text-white mr-1">Project</span>Tracker
          </div>
          <p className="text-xs text-slate-500 mt-1">Olá, {currentUser.name}</p>
          <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 border border-slate-700 px-2 py-0.5 rounded-full mt-2 inline-block">
            {currentUser.role}
          </span>
        </div>
        <nav className="flex-1 mt-6">
          <NavItem id="tracker" label="Projetar" icon={PenTool} />
          <NavItem id="history" label="Histórico" icon={History} />
          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
          <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4">
        {/* Logo Mobile */}
        <img 
            src="https://placehold.co/120x40/transparent/white?text=LOGO" 
            alt="Logo" 
            className="h-8 w-auto object-contain" 
        />
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden">
          <nav className="flex flex-col">
            <NavItem id="tracker" label="Projetar" icon={PenTool} />
            <NavItem id="history" label="Histórico" icon={History} />
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <button 
              onClick={handleLogout}
              className="flex items-center w-full px-6 py-4 text-left text-red-400 hover:bg-slate-800"
            >
              <LogOut className="w-5 h-5 mr-3" />
              Sair
            </button>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab: Always rendered, hidden via CSS to preserve timer state */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6">
              <h2 className="text-2xl font-bold text-gray-800">Nova Liberação</h2>
              <p className="text-gray-500">Logado como: <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
            </div>
            <ProjectTracker 
              onSave={handleProjectSave} 
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
            <div className="space-y-6">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Histórico de Liberações</h2>
                <p className="text-gray-500">
                  {currentUser.role === 'GESTOR' 
                    ? "Visão geral de todas as liberações da equipe." 
                    : "Consulte suas liberações passadas."}
                </p>
              </div>
              <ProjectHistory data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="space-y-6">
               <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Painel de Desempenho</h2>
                <p className="text-gray-500">
                  {currentUser.role === 'GESTOR' ? "Indicadores globais da equipe." : "Seus indicadores de produtividade."}
                </p>
              </div>
              <Dashboard data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'issues' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-800">Gestão de Qualidade</h2>
                   <p className="text-gray-500">Reporte e analise os problemas ocorridos.</p>
                </div>
                <div className="bg-gray-200 p-1 rounded-lg inline-flex">
                  <button 
                    onClick={() => setIssueTab('new')}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'new' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Novo Registro
                  </button>
                  <button 
                    onClick={() => setIssueTab('history')}
                     className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Histórico de Problemas
                  </button>
                </div>
              </div>

              {issueTab === 'new' ? (
                <IssueReporter onReport={handleIssueReport} />
              ) : (
                <IssueHistory data={displayData} currentUser={currentUser} />
              )}
            </div>
          )}

          {activeTab === 'innovations' && (
             <InnovationManager 
                innovations={displayData.innovations} 
                onAdd={handleInnovationAdd}
                onStatusChange={handleInnovationStatusChange}
                currentUser={currentUser}
             />
          )}

          {activeTab === 'team' && currentUser.role === 'GESTOR' && (
             <div className="space-y-6">
                <div className="mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">Gestão de Equipe</h2>
                  <p className="text-gray-500">Adicione novos membros e gerencie permissões de acesso.</p>
                </div>
                <UserManagement />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

