export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const user = await authenticateUser(username, password);
      if (user) {
        onLogin(user);
      } else {
        setError('Usuário ou senha inválidos');
      }
    } catch (err) {
      setError('Erro ao conectar ao servidor');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
      <div className="bg-slate-900 p-8 rounded-2xl shadow-2xl max-w-md w-full border border-slate-800">
        <div className="text-center mb-8">
          {/* Logo Container */}
          <div className="flex justify-center mb-6">
             <img 
               src={logoImg} 
               alt="Logo" 
               className="h-24 w-auto object-contain"
             />
          </div>
          <h1 className="text-3xl font-bold text-white tracking-tight mb-2">Project<span className="text-blue-500">Tracker</span></h1>
          <p className="text-slate-400 text-sm">Entre com suas credenciais para continuar</p>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-900/30 border border-red-800 text-red-200 text-sm rounded-lg flex items-center justify-center">
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300 ml-1">Usuário</label>
            <div className="relative">
              <UserIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input 
                type="text" 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full pl-10 p-3 bg-slate-950 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Seu nome de usuário"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300 ml-1">Senha</label>
            <div className="relative">
              <Lock className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-10 p-3 bg-slate-950 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Sua senha"
                required
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-xl flex items-center justify-center transition-all shadow-lg hover:shadow-blue-500/20 disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {loading ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <LogIn className="w-5 h-5 mr-2" />}
            {loading ? 'Entrando...' : 'Acessar Sistema'}
          </button>
        </form>

        <div className="mt-8 text-center text-xs text-slate-600">
          ProjectTracker &copy; 2024
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PenTool, AlertOctagon, Menu, X, History, Users, LogOut, Lightbulb } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { IssueHistory } from './components/IssueHistory';
import { Dashboard } from './components/Dashboard';
import { ProjectHistory } from './components/ProjectHistory';
import { UserManagement } from './components/UserManagement';
import { InnovationManager } from './components/InnovationManager';
import { Login } from './components/Login';
import { fetchAppState, addProject, addIssue, addInnovation, updateInnovationStatus } from './services/storageService';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from './types';
import logoImg from './src/assets/logo.png'; // Caminho corrigido: ./src/assets/logo.png

const COMPANY_LOGO_URL = logoImg;

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); // Reload if user changes (or initial load)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    // GESTOR sees everything
    if (currentUser.role === 'GESTOR') {
      return data;
    }

    // PROJETISTA sees only their own items (mostly), but might see shared Innovations
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      innovations: data.innovations
    };
  }, [data, currentUser]);

  const handleProjectSave = async (project: ProjectSession) => {
    setIsLoading(true);
    const projectWithUser = { ...project, userId: currentUser?.id };

    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));

    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
      alert(`Projeto NS ${project.ns} salvo com sucesso!`);
    } catch (e) {
      alert("Erro ao salvar no banco de dados.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };

     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));

    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));

    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      alert("Erro ao salvar inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  }

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors border-r-4 ${
        activeTab === id 
          ? 'bg-slate-800 border-blue-500 text-blue-400 font-medium' 
          : 'border-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white shadow-xl">
        <div className="p-6 border-b border-slate-800">
          {/* Logo and Title Side by Side */}
          <div className="mb-6 flex items-center gap-3">
             <img 
               src={COMPANY_LOGO_URL}
               alt="Logo" 
               className="h-10 w-auto max-w-[50px] object-contain" 
             />
             <div className="flex flex-col">
                <span className="text-2xl font-bold text-white leading-none tracking-tight">
                  Project<span className="text-blue-500">Tracker</span>
                </span>
             </div>
          </div>

          <div className="flex items-center text-slate-500 text-xs mb-1 uppercase tracking-wider font-semibold">
            Painel de Controle
          </div>
          <p className="text-sm font-medium text-slate-200 truncate">{currentUser.name}</p>
          <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 bg-slate-800 border border-slate-700 px-2 py-0.5 rounded-full mt-2 inline-block">
            {currentUser.role}
          </span>
        </div>
        <nav className="flex-1 mt-6 overflow-y-auto">
          <NavItem id="tracker" label="Projetar" icon={PenTool} />
          <NavItem id="history" label="Histórico" icon={History} />
          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
          <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 hover:bg-slate-800/50 p-2 rounded-lg font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4 shadow-md">
        {/* Logo Mobile */}
        <div className="h-8 flex items-center gap-2">
            <img 
                src={COMPANY_LOGO_URL} 
                alt="Logo" 
                className="h-full w-auto object-contain"
            />
            <span className="text-lg font-bold text-white">
                Project<span className="text-blue-500">Tracker</span>
            </span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white transition-colors">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden animate-in slide-in-from-right duration-200">
          <nav className="flex flex-col h-full overflow-y-auto">
            <NavItem id="tracker" label="Projetar" icon={PenTool} />
            <NavItem id="history" label="Histórico" icon={History} />
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <div className="mt-auto p-6 border-t border-slate-800">
              <button 
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-3 text-left text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
              >
                <LogOut className="w-5 h-5 mr-3" />
                Sair
              </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all bg-gray-50 min-h-screen">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Nova Liberação</h2>
                <p className="text-gray-500">Bem-vindo, <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
              </div>
            </div>
            <ProjectTracker 
              onSave={handleProjectSave} 
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
            <div className="space-y-6">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Histórico de Liberações</h2>
                <p className="text-gray-500">
                  {currentUser.role === 'GESTOR' 
                    ? "Visão geral de todas as liberações da equipe." 
                    : "Consulte suas liberações passadas."}
                </p>
              </div>
              <ProjectHistory data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="space-y-6">
               <div className="mb-6 flex items-center gap-4">
                 {/* Logo Container com fundo escuro (slate-900) */}
                 <div className="bg-slate-900 p-2 rounded-xl shadow-sm border border-slate-800">
                    <img 
                      src={COMPANY_LOGO_URL}
                      alt="Logo" 
                      className="h-12 w-auto object-contain" 
                    />
                 </div>
                 <div>
                    <h2 className="text-2xl font-bold text-gray-800">Painel de Desempenho</h2>
                    <p className="text-gray-500">
                      {currentUser.role === 'GESTOR' ? "Indicadores globais da equipe." : "Seus indicadores de produtividade."}
                    </p>
                 </div>
              </div>
              <Dashboard data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'issues' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-800">Gestão de Qualidade</h2>
                   <p className="text-gray-500">Reporte e analise os problemas ocorridos.</p>
                </div>
                <div className="bg-gray-200 p-1 rounded-lg inline-flex">
                  <button 
                    onClick={() => setIssueTab('new')}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'new' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Novo Registro
                  </button>
                  <button 
                    onClick={() => setIssueTab('history')}
                     className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Histórico de Problemas
                  </button>
                </div>
              </div>

              {issueTab === 'new' ? (
                <IssueReporter onReport={handleIssueReport} />
              ) : (
                <IssueHistory data={displayData} currentUser={currentUser} />
              )}
            </div>
          )}

          {activeTab === 'innovations' && (
             <InnovationManager 
                innovations={displayData.innovations} 
                onAdd={handleInnovationAdd}
                onStatusChange={handleInnovationStatusChange}
                currentUser={currentUser}
             />
          )}

          {activeTab === 'team' && currentUser.role === 'GESTOR' && (
             <div className="space-y-6">
                <div className="mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">Gestão de Equipe</h2>
                  <p className="text-gray-500">Adicione novos membros e gerencie permissões de acesso.</p>
                </div>
                <UserManagement />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Square, Clock, AlertCircle, Timer, Hash, Truck, Maximize2 } from 'lucide-react';
import { ProjectType, ProjectSession, PauseRecord, ImplementType } from '../types';
import { PROJECT_TYPES, IMPLEMENT_TYPES } from '../constants';

// SUBSTITUA ISSO PELA SUA URL DO WEBHOOK DO TEAMS
// (Crie um no Teams: Canal -> Conectores -> Incoming Webhook)
const TEAMS_WEBHOOK_URL = "https://outlook.office.com/webhook/YOUR_WEBHOOK_URL_HERE";

interface ProjectTrackerProps {
  onSave: (project: ProjectSession) => void;
  isVisible: boolean;
  onNavigateBack: () => void;
}

export const ProjectTracker: React.FC<ProjectTrackerProps> = ({ onSave, isVisible, onNavigateBack }) => {
  const [status, setStatus] = useState<'IDLE' | 'RUNNING' | 'PAUSED'>('IDLE');

  // Form Data
  const [ns, setNs] = useState('');
  const [projectCode, setProjectCode] = useState('');
  const [type, setType] = useState<ProjectType>(ProjectType.RELEASE);
  const [implementType, setImplementType] = useState<ImplementType>(ImplementType.BASE);
  const [notes, setNotes] = useState('');

  // Timer Data
  const [startTime, setStartTime] = useState<string | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [pauses, setPauses] = useState<PauseRecord[]>([]);

  // Pause Logic
  const [showPauseModal, setShowPauseModal] = useState(false);
  const [pauseReason, setPauseReason] = useState('');
  const [tempPauseTime, setTempPauseTime] = useState<number | null>(null);

  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (status === 'RUNNING') {
      timerRef.current = setInterval(() => {
        setElapsedSeconds(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status]);

  const handleStart = () => {
    if (!ns.trim()) {
      alert("Por favor, informe o NS do projeto antes de começar.");
      return;
    }
    setStartTime(new Date().toISOString());
    setStatus('RUNNING');
  };

  const initiatePause = () => {
    setStatus('PAUSED');
    setTempPauseTime(Date.now());
    // Immediate pause, no modal
  };

  const handleResume = () => {
    if (!pauseReason.trim()) return;

    const now = Date.now();
    const duration = tempPauseTime ? Math.floor((now - tempPauseTime) / 1000) : 0;

    setPauses(prev => [...prev, {
      reason: pauseReason,
      timestamp: new Date(tempPauseTime || now).toISOString(),
      durationSeconds: duration
    }]);

    setPauseReason('');
    setTempPauseTime(null);
    setShowPauseModal(false);
    setStatus('RUNNING');
  };

  const sendTeamsNotification = async (project: ProjectSession) => {
    // Basic validation to avoid sending if URL isn't set (or is the placeholder)
    if (!TEAMS_WEBHOOK_URL || TEAMS_WEBHOOK_URL.includes("YOUR_WEBHOOK_URL_HERE")) {
      console.warn("Teams Webhook URL not configured in code.");
      return;
    }

    const duration = formatTime(project.totalActiveSeconds);

    const message = {
      "@type": "MessageCard",
      "@context": "http://schema.org/extensions",
      "themeColor": "0076D7",
      "summary": "Projeto Finalizado",
      "sections": [{
        "activityTitle": "✅ Projeto Finalizado",
        "activitySubtitle": `DesignTrack Pro`,
        "facts": [
          { "name": "NS:", "value": project.ns },
          { "name": "Código:", "value": project.projectCode || "N/A" },
          { "name": "Tipo:", "value": project.type },
          { "name": "Implemento:", "value": project.implementType || "N/A" },
          { "name": "Duração:", "value": duration },
          { "name": "Pausas:", "value": `${project.pauses.length}` }
        ],
        "markdown": true
      }]
    };

    try {
      await fetch(TEAMS_WEBHOOK_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(message)
      });
      console.log("Notificação enviada para o Teams");
    } catch (error) {
      console.error("Erro ao enviar notificação para Teams (provável erro de CORS ou URL inválida):", error);
    }
  };

  const handleFinish = async () => {
    if (!startTime) return;

    const newProject: ProjectSession = {
      id: crypto.randomUUID(),
      ns,
      projectCode,
      type,
      implementType,
      startTime,
      endTime: new Date().toISOString(),
      totalActiveSeconds: elapsedSeconds,
      pauses,
      status: 'COMPLETED',
      notes
    };

    // Save locally
    onSave(newProject);

    // Send to Teams (Fire and forget, don't await blocking UI)
    sendTeamsNotification(newProject);

    resetForm();
  };

  const resetForm = () => {
    setStatus('IDLE');
    setNs('');
    setProjectCode('');
    setNotes('');
    setElapsedSeconds(0);
    setStartTime(null);
    setPauses([]);
    setPauseReason('');
    setShowPauseModal(false);
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <>
      <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 relative">
        <h2 className="text-xl font-bold mb-4 flex items-center text-gray-800">
          <Clock className="w-6 h-6 mr-2 text-blue-600" />
          Rastreador de Liberação
        </h2>

        {status === 'IDLE' ? (
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">NS do Produto</label>
                <input 
                  type="text" 
                  value={ns}
                  onChange={e => setNs(e.target.value)}
                  className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Ex: 123456"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Cód. Projeto</label>
                <div className="relative">
                  <Hash className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                  <input 
                    type="text" 
                    value={projectCode}
                    onChange={e => setProjectCode(e.target.value)}
                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    placeholder="Ex: PRJ-001"
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Projeto</label>
                <select 
                  value={type}
                  onChange={e => setType(e.target.value as ProjectType)}
                  className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  {PROJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Implemento</label>
                <div className="relative">
                  <Truck className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                  <select 
                    value={implementType}
                    onChange={e => setImplementType(e.target.value as ImplementType)}
                    className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {IMPLEMENT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
              </div>
            </div>
            <button 
              onClick={handleStart}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
            >
              <Play className="w-5 h-5 mr-2" />
              Começar Projeto
            </button>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex flex-col items-center justify-center bg-gray-50 p-6 rounded-xl border border-gray-200">
              <span className="text-sm text-gray-500 font-medium tracking-wider uppercase mb-1">{status === 'PAUSED' ? 'PROJETO PAUSADO' : 'EM ANDAMENTO'}</span>
              <div className={`text-6xl font-mono font-bold ${status === 'PAUSED' ? 'text-yellow-600' : 'text-blue-600'}`}>
                {formatTime(elapsedSeconds)}
              </div>
              <div className="text-gray-600 mt-2 font-medium flex gap-2 flex-wrap justify-center">
                <span>NS: {ns}</span>
                {projectCode && <span className="text-gray-400">• Cód: {projectCode}</span>}
                <span className="text-gray-400">• {type}</span>
                <span className="text-gray-400">• {implementType}</span>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              {status === 'RUNNING' && (
                <button 
                  onClick={initiatePause}
                  className="bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
                >
                  <Pause className="w-5 h-5 mr-2" />
                  Pausar
                </button>
              )}

              {status === 'PAUSED' && (
                <button 
                onClick={() => setShowPauseModal(true)}
                className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
              >
                <Play className="w-5 h-5 mr-2" />
                Retomar
              </button>
              )}

              <button 
                onClick={handleFinish}
                disabled={status === 'PAUSED'}
                className={`font-bold py-3 rounded-lg flex items-center justify-center transition-colors text-white ${status === 'PAUSED' ? 'bg-gray-400 cursor-not-allowed' : 'bg-red-600 hover:bg-red-700'}`}
              >
                <Square className="w-5 h-5 mr-2 fill-current" />
                Finalizar
              </button>
            </div>
          </div>
        )}

        {/* Resume Modal */}
        {showPauseModal && (
          <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
            <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200">
              <h3 className="text-lg font-bold mb-4 flex items-center text-blue-600">
                <Play className="w-5 h-5 mr-2" />
                Retomar Projeto
              </h3>

              <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 mb-4 flex items-center justify-between">
                <div className="flex items-center text-blue-800">
                  <Timer className="w-4 h-4 mr-2" />
                  <span className="text-sm font-medium">Tempo Trabalhado:</span>
                </div>
                <span className="text-xl font-mono font-bold text-blue-700">
                  {formatTime(elapsedSeconds)}
                </span>
              </div>

              <p className="text-sm text-gray-600 mb-2">Informe o motivo da pausa para continuar:</p>
              <input 
                type="text" 
                autoFocus
                value={pauseReason}
                onChange={e => setPauseReason(e.target.value)}
                placeholder="Ex: Ir a fabrica, Reunião, Almoço..."
                className="w-full p-3 border rounded-lg mb-6 focus:ring-2 focus:ring-blue-500 outline-none"
              />

              <div className="flex justify-end gap-2">
                <button 
                  onClick={() => setShowPauseModal(false)}
                  className="text-gray-500 px-4 py-2 rounded-lg font-medium hover:bg-gray-100"
                >
                  Cancelar
                </button>
                <button 
                  onClick={handleResume}
                  disabled={!pauseReason.trim()}
                  className="bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700 disabled:opacity-50"
                >
                  Salvar e Retomar
                </button>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Floating Timer Pop-up (Visible only when tracker is hidden and running) */}
      {!isVisible && status === 'RUNNING' && (
        <div 
          onClick={onNavigateBack}
          className="fixed bottom-6 right-6 z-50 bg-slate-900 text-white p-4 rounded-xl shadow-2xl cursor-pointer hover:bg-slate-800 transition-all transform hover:scale-105 group border border-slate-700 ring-2 ring-blue-500/50"
        >
          <div className="flex items-center justify-between mb-2 gap-4">
            <div className="flex items-center text-green-400 text-xs font-bold uppercase tracking-wider animate-pulse">
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
              Em Andamento
            </div>
            <Maximize2 className="w-4 h-4 text-gray-400 group-hover:text-white" />
          </div>
          <div className="font-mono text-3xl font-bold mb-1">
            {formatTime(elapsedSeconds)}
          </div>
          <div className="text-xs text-gray-400 mb-1">
            NS: {ns} • {implementType}
          </div>
          <div className="text-xs text-blue-400 font-medium mt-2 border-t border-slate-700 pt-2">
            Clique para retornar
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PenTool, AlertOctagon, Menu, X, History, Users, LogOut, Lightbulb } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { IssueHistory } from './components/IssueHistory';
import { Dashboard } from './components/Dashboard';
import { ProjectHistory } from './components/ProjectHistory';
import { UserManagement } from './components/UserManagement';
import { InnovationManager } from './components/InnovationManager';
import { Login } from './components/Login';
import { fetchAppState, addProject, addIssue, addInnovation, updateInnovationStatus } from './services/storageService';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from './types';

// Definindo o caminho como string direta para evitar erros de importação de módulo
const COMPANY_LOGO_URL = "/src/assets/logo.png";

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); // Reload if user changes (or initial load)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    // GESTOR sees everything
    if (currentUser.role === 'GESTOR') {
      return data;
    }

    // PROJETISTA sees only their own items (mostly), but might see shared Innovations
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      innovations: data.innovations
    };
  }, [data, currentUser]);

  const handleProjectSave = async (project: ProjectSession) => {
    setIsLoading(true);
    const projectWithUser = { ...project, userId: currentUser?.id };

    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));

    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
      alert(`Projeto NS ${project.ns} salvo com sucesso!`);
    } catch (e) {
      alert("Erro ao salvar no banco de dados.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };

     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));

    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));

    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      alert("Erro ao salvar inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  }

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors border-r-4 ${
        activeTab === id 
          ? 'bg-slate-800 border-blue-500 text-blue-400 font-medium' 
          : 'border-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white shadow-xl">
        <div className="p-6 border-b border-slate-800">
          {/* Logo and Title Side by Side */}
          <div className="mb-6 flex items-center gap-3">
             <img 
               src={COMPANY_LOGO_URL}
               alt="Logo" 
               className="h-10 w-auto max-w-[50px] object-contain" 
             />
             <div className="flex flex-col">
                <span className="text-2xl font-bold text-white leading-none tracking-tight">
                  Project<span className="text-blue-500">Tracker</span>
                </span>
             </div>
          </div>

          <div className="flex items-center text-slate-500 text-xs mb-1 uppercase tracking-wider font-semibold">
            Painel de Controle
          </div>
          <p className="text-sm font-medium text-slate-200 truncate">{currentUser.name}</p>
          <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 bg-slate-800 border border-slate-700 px-2 py-0.5 rounded-full mt-2 inline-block">
            {currentUser.role}
          </span>
        </div>
        <nav className="flex-1 mt-6 overflow-y-auto">
          <NavItem id="tracker" label="Projetar" icon={PenTool} />
          <NavItem id="history" label="Histórico" icon={History} />
          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
          <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 hover:bg-slate-800/50 p-2 rounded-lg font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4 shadow-md">
        {/* Logo Mobile */}
        <div className="h-8 flex items-center gap-2">
            <img 
                src={COMPANY_LOGO_URL} 
                alt="Logo" 
                className="h-full w-auto object-contain"
            />
            <span className="text-lg font-bold text-white">
                Project<span className="text-blue-500">Tracker</span>
            </span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white transition-colors">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden animate-in slide-in-from-right duration-200">
          <nav className="flex flex-col h-full overflow-y-auto">
            <NavItem id="tracker" label="Projetar" icon={PenTool} />
            <NavItem id="history" label="Histórico" icon={History} />
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <div className="mt-auto p-6 border-t border-slate-800">
              <button 
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-3 text-left text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
              >
                <LogOut className="w-5 h-5 mr-3" />
                Sair
              </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all bg-gray-50 min-h-screen">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Nova Liberação</h2>
                <p className="text-gray-500">Bem-vindo, <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
              </div>
            </div>
            <ProjectTracker 
              onSave={handleProjectSave} 
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
            <div className="space-y-6">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Histórico de Liberações</h2>
                <p className="text-gray-500">
                  {currentUser.role === 'GESTOR' 
                    ? "Visão geral de todas as liberações da equipe." 
                    : "Consulte suas liberações passadas."}
                </p>
              </div>
              <ProjectHistory data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="space-y-6">
               <div className="mb-6 flex items-center gap-4">
                 {/* Logo Container com fundo escuro (slate-900) */}
                 <div className="bg-slate-900 p-2 rounded-xl shadow-sm border border-slate-800">
                    <img 
                      src={COMPANY_LOGO_URL}
                      alt="Logo" 
                      className="h-12 w-auto object-contain" 
                    />
                 </div>
                 <div>
                    <h2 className="text-2xl font-bold text-gray-800">Painel de Desempenho</h2>
                    <p className="text-gray-500">
                      {currentUser.role === 'GESTOR' ? "Indicadores globais da equipe." : "Seus indicadores de produtividade."}
                    </p>
                 </div>
              </div>
              <Dashboard data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'issues' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-800">Gestão de Qualidade</h2>
                   <p className="text-gray-500">Reporte e analise os problemas ocorridos.</p>
                </div>
                <div className="bg-gray-200 p-1 rounded-lg inline-flex">
                  <button 
                    onClick={() => setIssueTab('new')}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'new' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Novo Registro
                  </button>
                  <button 
                    onClick={() => setIssueTab('history')}
                     className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Histórico de Problemas
                  </button>
                </div>
              </div>

              {issueTab === 'new' ? (
                <IssueReporter onReport={handleIssueReport} />
              ) : (
                <IssueHistory data={displayData} currentUser={currentUser} />
              )}
            </div>
          )}

          {activeTab === 'innovations' && (
             <InnovationManager 
                innovations={displayData.innovations} 
                onAdd={handleInnovationAdd}
                onStatusChange={handleInnovationStatusChange}
                currentUser={currentUser}
             />
          )}

          {activeTab === 'team' && currentUser.role === 'GESTOR' && (
             <div className="space-y-6">
                <div className="mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">Gestão de Equipe</h2>
                  <p className="text-gray-500">Adicione novos membros e gerencie permissões de acesso.</p>
                </div>
                <UserManagement />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

