export default App;

import React, { useState } from 'react';
import { Lock, User as UserIcon, LogIn, Loader2 } from 'lucide-react';
import { authenticateUser } from '../services/storageService';
import { User } from '../types';
import logoImg from '../src/assets/logo.png';

interface LoginProps {
  onLogin: (user: User) => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const user = await authenticateUser(username, password);
      if (user) {
        onLogin(user);
      } else {
        setError('Usuário ou senha inválidos');
      }
    } catch (err) {
      setError('Erro ao conectar ao servidor');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
      <div className="bg-slate-900 p-8 rounded-2xl shadow-2xl max-w-md w-full border border-slate-800">
        <div className="text-center mb-8">
          {/* Logo Container */}
          <div className="flex justify-center mb-6">
             <img 
               src={logoImg} 
               alt="Logo" 
               className="h-24 w-auto object-contain"
             />
          </div>
          <h1 className="text-3xl font-bold text-white tracking-tight mb-2">Project<span className="text-blue-500">Tracker</span></h1>
          <p className="text-slate-400 text-sm">Entre com suas credenciais para continuar</p>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-900/30 border border-red-800 text-red-200 text-sm rounded-lg flex items-center justify-center">
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300 ml-1">Usuário</label>
            <div className="relative">
              <UserIcon className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input 
                type="text" 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full pl-10 p-3 bg-slate-950 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Seu nome de usuário"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300 ml-1">Senha</label>
            <div className="relative">
              <Lock className="absolute left-3 top-3 w-5 h-5 text-slate-500" />
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-10 p-3 bg-slate-950 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                placeholder="Sua senha"
                required
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-xl flex items-center justify-center transition-all shadow-lg hover:shadow-blue-500/20 disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {loading ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <LogIn className="w-5 h-5 mr-2" />}
            {loading ? 'Entrando...' : 'Acessar Sistema'}
          </button>
        </form>

        <div className="mt-8 text-center text-xs text-slate-600">
          ProjectTracker &copy; 2024
        </div>
      </div>
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from '../types';

// Supabase Configuration
const SUPABASE_URL = 'https://vfctdeaeahhermgzlaml.supabase.co';
const SUPABASE_KEY = 'sb_publishable_9vJxl7Ogf1ZZ9mlNyHj6DQ_pW3HJhK2';

export const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

const defaultState: AppState = {
  projects: [],
  issues: [],
  innovations: []
};

// --- DATA MANAGEMENT ---

export const fetchAppState = async (): Promise<AppState> => {
  try {
    // Fetch Projects
    const { data: projectsData, error: projectsError } = await supabase
      .from('projects')
      .select('*')
      .order('start_time', { ascending: false });

    if (projectsError) throw projectsError;

    // Fetch Issues
    const { data: issuesData, error: issuesError } = await supabase
      .from('issues')
      .select('*')
      .order('date', { ascending: false });

    if (issuesError) throw issuesError;

    // Fetch Innovations
    const { data: innovationsData, error: innovationsError } = await supabase
      .from('innovations')
      .select('*')
      .order('created_at', { ascending: false });

    // Note: If table doesn't exist yet, this might error gracefully or need handling
    // We assume table exists based on SQL instructions provided.

    // Map DB columns (snake_case) to Types (camelCase)
    const projects: ProjectSession[] = (projectsData || []).map((p: any) => ({
      id: p.id,
      ns: p.ns,
      projectCode: p.project_code,
      type: p.type,
      implementType: p.implement_type,
      startTime: p.start_time,
      endTime: p.end_time,
      totalActiveSeconds: p.total_active_seconds,
      pauses: typeof p.pauses === 'string' ? JSON.parse(p.pauses) : p.pauses,
      status: p.status,
      notes: p.notes,
      userId: p.user_id
    }));

    const issues: IssueRecord[] = (issuesData || []).map((i: any) => ({
      id: i.id,
      projectNs: i.project_ns,
      type: i.type,
      description: i.description,
      date: i.date,
      reportedBy: i.reported_by
    }));

    const innovations: InnovationRecord[] = (innovationsData || []).map((inv: any) => ({
      id: inv.id,
      title: inv.title,
      description: inv.description,
      type: inv.type,
      currentCost: inv.current_cost,
      projectedCost: inv.projected_cost,
      costDifference: inv.cost_difference,
      status: inv.status,
      authorId: inv.author_id,
      createdAt: inv.created_at
    }));

    return { projects, issues, innovations };
  } catch (error) {
    console.error("Failed to load data from Supabase", error);
    return defaultState;
  }
};

export const addProject = async (project: ProjectSession): Promise<AppState> => {
  try {
    const { error } = await supabase.from('projects').insert([{
      id: project.id,
      ns: project.ns,
      project_code: project.projectCode,
      type: project.type,
      implement_type: project.implementType,
      start_time: project.startTime,
      end_time: project.endTime,
      total_active_seconds: project.totalActiveSeconds,
      pauses: project.pauses, // Supabase handles JSON array automatically if column is jsonb
      status: project.status,
      notes: project.notes,
      user_id: project.userId
    }]);

    if (error) throw error;

    return fetchAppState();
  } catch (error) {
    console.error("Failed to add project", error);
    return fetchAppState();
  }
};

export const updateProject = async (project: ProjectSession): Promise<AppState> => {
  try {
    const { error } = await supabase
      .from('projects')
      .update({
        ns: project.ns,
        project_code: project.projectCode,
        type: project.type,
        implement_type: project.implementType,
        end_time: project.endTime,
        total_active_seconds: project.totalActiveSeconds,
        pauses: project.pauses,
        status: project.status,
        notes: project.notes
      })
      .eq('id', project.id);

    if (error) throw error;

    return fetchAppState();
  } catch (error) {
    console.error("Failed to update project", error);
    return fetchAppState();
  }
};

export const addIssue = async (issue: IssueRecord): Promise<AppState> => {
