const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); // Reload if user changes (or initial load)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    // GESTOR sees everything
    if (currentUser.role === 'GESTOR') {
      return data;
    }

    // PROJETISTA sees only their own items (mostly), but might see shared Innovations
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      innovations: data.innovations
    };
  }, [data, currentUser]);

  // --- HANDLERS ---

  const handleProjectCreate = async (project: ProjectSession) => {
    const projectWithUser = { ...project, userId: currentUser?.id };
    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));
    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao criar projeto.");
    }
  };

  const handleProjectUpdate = async (project: ProjectSession) => {
    setData(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === project.id ? project : p)
    }));
    try {
        const updatedData = await updateProject(project);
        setData(updatedData);
        if (project.status === 'COMPLETED') {
             alert(`Projeto NS ${project.ns} finalizado com sucesso!`);
        }
    } catch (e) {
        alert("Erro ao atualizar projeto.");
    }
  };

  const handleProjectDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar este projeto? Essa ação não pode ser desfeita.")) return;

    setIsLoading(true);
    try {
      const updatedData = await deleteProject(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar projeto.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };
     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));
    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar esta ocorrência?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteIssue(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar ocorrência.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));
    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      alert("Erro ao salvar inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleInnovationDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja excluir esta inovação?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteInnovation(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao excluir inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors border-r-4 ${
        activeTab === id 
          ? 'bg-slate-800 border-blue-500 text-blue-400 font-medium' 
          : 'border-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white shadow-xl">
        <div className="p-6 border-b border-slate-800">
          <div className="mb-6 flex items-center gap-3">
             <img 
               src={COMPANY_LOGO_URL}
               alt="Logo" 
               className="h-10 w-auto max-w-[50px] object-contain" 
             />
             <div className="flex flex-col">
                <span className="text-2xl font-bold text-white leading-none tracking-tight">
                  Project<span className="text-blue-500">Tracker</span>
                </span>
             </div>
          </div>

          <div className="flex items-center text-slate-500 text-xs mb-1 uppercase tracking-wider font-semibold">
            Painel de Controle
          </div>
          <p className="text-sm font-medium text-slate-200 truncate">{currentUser.name}</p>
          <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 bg-slate-800 border border-slate-700 px-2 py-0.5 rounded-full mt-2 inline-block">
            {currentUser.role}
          </span>
        </div>
        <nav className="flex-1 mt-6 overflow-y-auto">
          <NavItem id="tracker" label="Projetar" icon={PenTool} />
          <NavItem id="history" label="Histórico" icon={History} />
          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
          <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 hover:bg-slate-800/50 p-2 rounded-lg font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4 shadow-md">
        <div className="h-8 flex items-center gap-2">
            <img 
                src={COMPANY_LOGO_URL} 
                alt="Logo" 
                className="h-full w-auto object-contain"
            />
            <span className="text-lg font-bold text-white">
                Project<span className="text-blue-500">Tracker</span>
            </span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white transition-colors">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden animate-in slide-in-from-right duration-200">
          <nav className="flex flex-col h-full overflow-y-auto">
            <NavItem id="tracker" label="Projetar" icon={PenTool} />
            <NavItem id="history" label="Histórico" icon={History} />
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <div className="mt-auto p-6 border-t border-slate-800">
              <button 
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-3 text-left text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
              >
                <LogOut className="w-5 h-5 mr-3" />
                Sair
              </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all bg-gray-50 min-h-screen">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Área de Projeto</h2>
                <p className="text-gray-500">Bem-vindo, <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
              </div>
            </div>
            <ProjectTracker 
              existingProjects={displayData.projects}
              onCreate={handleProjectCreate}
              onUpdate={handleProjectUpdate}
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
            <div className="space-y-6">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Histórico de Liberações</h2>
                <p className="text-gray-500">
                  {currentUser.role === 'GESTOR' 
                    ? "Visão geral de todas as liberações da equipe." 
                    : "Consulte suas liberações passadas."}
                </p>
              </div>
              <ProjectHistory 
                data={displayData} 
                currentUser={currentUser} 
                onDelete={handleProjectDelete}
              />
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="space-y-6">
               <div className="mb-6 flex items-center gap-4">
                 <div className="bg-slate-900 p-2 rounded-xl shadow-sm border border-slate-800">
                    <img 
                      src={COMPANY_LOGO_URL}
                      alt="Logo" 
                      className="h-12 w-auto object-contain" 
                    />
                 </div>
                 <div>
                    <h2 className="text-2xl font-bold text-gray-800">Painel de Desempenho</h2>
                    <p className="text-gray-500">
                      {currentUser.role === 'GESTOR' ? "Indicadores globais da equipe." : "Seus indicadores de produtividade."}
                    </p>
                 </div>
              </div>
              <Dashboard data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'issues' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-800">Gestão de Qualidade</h2>
                   <p className="text-gray-500">Reporte e analise os problemas ocorridos.</p>
                </div>
                <div className="bg-gray-200 p-1 rounded-lg inline-flex">
                  <button 
                    onClick={() => setIssueTab('new')}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'new' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Novo Registro
                  </button>
                  <button 
                    onClick={() => setIssueTab('history')}
                     className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Histórico de Problemas
                  </button>
                </div>
              </div>

              {issueTab === 'new' ? (
                <IssueReporter onReport={handleIssueReport} />
              ) : (
                <IssueHistory 
                  data={displayData} 
                  currentUser={currentUser} 
                  onDelete={handleIssueDelete}
                />
              )}
            </div>
          )}

          {activeTab === 'innovations' && (
             <InnovationManager 
                innovations={displayData.innovations} 
                onAdd={handleInnovationAdd}
                onStatusChange={handleInnovationStatusChange}
                onDelete={handleInnovationDelete}
                currentUser={currentUser}
             />
          )}

          {activeTab === 'team' && currentUser.role === 'GESTOR' && (
             <div className="space-y-6">
                <div className="mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">Gestão de Equipe</h2>
                  <p className="text-gray-500">Adicione novos membros e gerencie permissões de acesso.</p>
                </div>
                <UserManagement />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Lightbulb, Plus, TrendingDown, TrendingUp, DollarSign, Calendar, User as UserIcon, Check, X, PlayCircle, Trash2, Calculator, ArrowRight } from 'lucide-react';
import { InnovationType, InnovationRecord, User, AppState, CalculationType } from '../types';
import { fetchUsers } from '../services/storageService';

interface InnovationManagerProps {
  innovations: InnovationRecord[];
  onAdd: (innovation: InnovationRecord) => void;
  onStatusChange: (id: string, status: string) => void;
  onDelete: (id: string) => void;
  currentUser: User;
}

export const InnovationManager: React.FC<InnovationManagerProps> = ({ innovations, onAdd, onStatusChange, onDelete, currentUser }) => {
  const [showForm, setShowForm] = useState(false);
  const [usersMap, setUsersMap] = useState<Record<string, string>>({});

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [type, setType] = useState<InnovationType>(InnovationType.PRODUCT_IMPROVEMENT);
  const [calculationType, setCalculationType] = useState<CalculationType>(CalculationType.RECURRING_MONTHLY);
  const [unitSavings, setUnitSavings] = useState<string>(''); // R$ value
  const [quantity, setQuantity] = useState<string>(''); // Qty
  const [investmentCost, setInvestmentCost] = useState<string>(''); // R$ Investment

  useEffect(() => {
    const load = async () => {
      const users = await fetchUsers();
      const map = users.reduce((acc, u) => ({ ...acc, [u.id]: u.name }), {} as Record<string, string>);
      setUsersMap(map);
    };
    load();
  }, []);

  // Sort innovations by date descending
  const sortedInnovations = useMemo(() => {
    return [...innovations].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [innovations]);

  // Calculate totals - ONLY APPROVED or IMPLEMENTED
  const totalStats = useMemo(() => {
    return innovations.reduce((acc, curr) => {
      if (curr.status === 'APPROVED' || curr.status === 'IMPLEMENTED') {
         return {
            savings: acc.savings + (curr.totalAnnualSavings || 0),
            count: acc.count + 1
         };
      }
      return acc;
    }, { savings: 0, count: 0 });
  }, [innovations]);

  // Preview Calculation for Form
  const previewAnnualSavings = useMemo(() => {
    const unit = parseFloat(unitSavings) || 0;
    const qty = parseFloat(quantity) || 0;

    if (calculationType === CalculationType.ONE_TIME) return unit;
    return unit * qty;
  }, [unitSavings, quantity, calculationType]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const unit = parseFloat(unitSavings) || 0;
    const qty = parseFloat(quantity) || 0;
    const invest = parseFloat(investmentCost) || 0;
    let total = 0;

    if (calculationType === CalculationType.ONE_TIME) {
        total = unit;
    } else {
        total = unit * qty;
    }

    const newRecord: InnovationRecord = {
      id: crypto.randomUUID(),
      title,
      description,
      type,

      calculationType,
      unitSavings: unit,
      quantity: calculationType === CalculationType.ONE_TIME ? 1 : qty,
      totalAnnualSavings: total,
      investmentCost: invest,

      status: 'PENDING',
      authorId: currentUser.id,
      createdAt: new Date().toISOString()
    };

    onAdd(newRecord);

    // Reset form
    setTitle('');
    setDescription('');
    setUnitSavings('');
    setQuantity('');
    setInvestmentCost('');
    setShowForm(false);
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const getStatusColor = (status: string) => {
      switch(status) {
          case 'APPROVED': return 'bg-blue-100 text-blue-700 border-blue-200';
          case 'IMPLEMENTED': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
          case 'REJECTED': return 'bg-red-50 text-red-600 border-red-100';
          default: return 'bg-gray-100 text-gray-700 border-gray-200';
      }
  }

  const getStatusLabel = (status: string) => {
      switch(status) {
          case 'APPROVED': return 'Aprovado';
          case 'IMPLEMENTED': return 'Implementado';
          case 'REJECTED': return 'Rejeitado';
          default: return 'Pendente';
      }
  }

  const getCalculationLabel = (type: CalculationType) => {
      switch(type) {
          case CalculationType.PER_UNIT: return 'unidades/ano';
          case CalculationType.RECURRING_MONTHLY: return 'meses/ano';
          default: return '';
      }
  }

  return (
    <div className="space-y-6">
      {/* Header & Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center">
            <Lightbulb className="w-6 h-6 mr-2 text-yellow-500" />
            Inovações e Melhorias
          </h2>
          <p className="text-gray-500 mt-1">Gerencie ideias e acompanhe o impacto financeiro real.</p>
        </div>

        <div className="bg-gradient-to-r from-emerald-500 to-teal-600 rounded-xl p-6 text-white shadow-lg relative overflow-hidden">
          <div className="relative z-10">
              <div className="text-emerald-100 text-sm font-medium mb-1 uppercase tracking-wider">Economia Anual (Aprovada)</div>
              <div className="text-4xl font-bold font-mono">{formatCurrency(totalStats.savings)}</div>
              <div className="text-emerald-100 text-xs mt-2 flex items-center">
                <Check className="w-4 h-4 mr-1" />
                {totalStats.count} inovações contabilizadas
              </div>
          </div>
          <TrendingDown className="absolute right-4 bottom-4 w-24 h-24 text-white/10" />
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex justify-end">
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-lg flex items-center transition-colors shadow-sm"
        >
          <Plus className="w-5 h-5 mr-2" />
          Nova Ideia / Melhoria
        </button>
      </div>

      {/* Form */}
      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-blue-100 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="font-bold text-lg mb-6 text-gray-800 flex items-center border-b pb-4">
            <Calculator className="w-5 h-5 mr-2 text-blue-600" />
            Calculadora de Economia
          </h3>
          <form onSubmit={handleSubmit} className="space-y-6">

            {/* Basic Info */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-700 mb-1">Título da Melhoria</label>
                <input 
                  type="text" 
                  value={title}
                  onChange={e => setTitle(e.target.value)}
                  className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Ex: Otimização de corte de chapa..."
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Inovação</label>
                <select 
                  value={type}
                  onChange={e => setType(e.target.value as InnovationType)}
                  className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                >
                  <option value={InnovationType.PRODUCT_IMPROVEMENT}>Melhoria de Produto</option>
                  <option value={InnovationType.PROCESS_OPTIMIZATION}>Otimização de Processo</option>
                  <option value={InnovationType.NEW_PROJECT}>Novo Projeto</option>
                </select>
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Custo de Investimento (Opcional)</label>
                 <div className="relative">
                   <span className="absolute left-3 top-3 text-gray-400">R$</span>
                   <input 
                    type="number" 
                    step="0.01"
                    value={investmentCost}
                    onChange={e => setInvestmentCost(e.target.value)}
                    className="w-full pl-10 p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    placeholder="0.00"
                  />
                </div>
              </div>
            </div>

            {/* Calculation Logic */}
            <div className="bg-gray-50 p-6 rounded-lg border border-gray-200">
                <h4 className="text-sm font-bold text-gray-700 mb-4 uppercase tracking-wider">Cálculo de Impacto Financeiro</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="md:col-span-1">
                        <label className="block text-sm font-medium text-gray-700 mb-1">Método de Cálculo</label>
                        <select 
                            value={calculationType}
                            onChange={e => setCalculationType(e.target.value as CalculationType)}
                            className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                        >
                            <option value={CalculationType.RECURRING_MONTHLY}>Recorrente (Mensal)</option>
                            <option value={CalculationType.PER_UNIT}>Por Unidade Produzida</option>
                            <option value={CalculationType.ONE_TIME}>Valor Único / Fixo</option>
                        </select>
                    </div>

                    <div className="md:col-span-1">
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                             {calculationType === CalculationType.PER_UNIT ? 'Economia por Unidade' : 
                              calculationType === CalculationType.RECURRING_MONTHLY ? 'Economia por Mês' : 
                              'Valor da Economia'}
                        </label>
                        <div className="relative">
                            <span className="absolute left-3 top-3 text-gray-500 font-bold">R$</span>
                            <input 
                                type="number" 
                                step="0.01"
                                value={unitSavings}
                                onChange={e => setUnitSavings(e.target.value)}
                                className="w-full pl-10 p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                placeholder="0.00"
                                required
                            />
                        </div>
                    </div>

                    <div className="md:col-span-1">
                        {calculationType !== CalculationType.ONE_TIME ? (
                            <>
                                <label className="block text-sm font-medium text-gray-700 mb-1">
                                    {calculationType === CalculationType.PER_UNIT ? 'Qtd. Produzida/Ano' : 'Meses Ativos/Ano'}
                                </label>
                                <input 
                                    type="number" 
                                    value={quantity}
                                    onChange={e => setQuantity(e.target.value)}
                                    className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                    placeholder={calculationType === CalculationType.PER_UNIT ? "Ex: 500" : "Ex: 12"}
                                    required
                                />
                            </>
                        ) : (
                             <div className="flex items-center h-full pt-6 text-gray-400 text-sm italic">
                                Cálculo de valor único.
                             </div>
                        )}
                    </div>
                </div>

                {/* Preview Banner */}
                <div className="mt-6 bg-blue-50 border border-blue-200 rounded-lg p-4 flex items-center justify-between">
                    <div>
                        <div className="text-xs text-blue-600 font-bold uppercase">Impacto Anual Estimado</div>
                        <div className="text-sm text-blue-800 mt-1">
                            {calculationType === CalculationType.ONE_TIME 
                                ? "Valor Fixo Único"
                                : `${formatCurrency(parseFloat(unitSavings) || 0)} x ${parseFloat(quantity) || 0} ${getCalculationLabel(calculationType)}`
                            }
                        </div>
                    </div>
                    <div className="flex items-center text-2xl font-bold text-blue-700">
                        <ArrowRight className="w-5 h-5 mr-2 text-blue-400" />
                        {formatCurrency(previewAnnualSavings)}
                    </div>
                </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Detalhes Técnicos</label>
              <textarea 
                value={description}
                onChange={e => setDescription(e.target.value)}
                rows={3}
                className="w-full p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Descreva como essa economia será alcançada..."
                required
              />
            </div>

            <div className="flex justify-end gap-3 pt-4 border-t">
               <button 
                  type="button"
                  onClick={() => setShowForm(false)}
                  className="px-6 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors font-medium"
                >
                  Cancelar
                </button>
