                                             {v.type}
                                         </span>
                                     </td>
                                     <td className="p-3 text-center">
                                         <button 
                                            onClick={() => handleToggleVariationFiles(v.id)}
                                            title={v.filesGenerated ? "Arquivos Gerados (Clique para desfazer)" : "Marcar arquivos como gerados"}
                                            className={`flex items-center justify-center p-2 rounded mx-auto transition-colors ${
                                                v.filesGenerated 
                                                ? 'bg-green-100 text-green-600 hover:bg-green-200 shadow-sm' 
                                                : 'bg-gray-100 text-gray-400 hover:bg-gray-200'
                                            }`}
                                         >
                                            {v.filesGenerated ? <FileCheck className="w-4 h-4" /> : <Square className="w-4 h-4" />}
                                            <span className="ml-1 text-xs font-bold">{v.filesGenerated ? 'OK' : 'Pendente'}</span>
                                         </button>
                                     </td>
                                     <td className="p-3 text-right">
                                         <button 
                                            onClick={() => handleDeleteVariation(v.id)}
                                            className="text-gray-400 hover:text-red-500"
                                         >
                                             <Trash2 className="w-4 h-4" />
                                         </button>
                                     </td>
                                 </tr>
                             ))}
                             {activeProject.variations.length === 0 && (
                                 <tr>
                                     <td colSpan={6} className="p-6 text-center text-gray-400 italic">
                                         Nenhuma variação registrada para este projeto ainda.
                                     </td>
                                 </tr>
                             )}
                         </tbody>
                     </table>
                 </div>
            </div>
        </div>
      )}

      {/* Pause Modal */}
      {showPauseModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200">
            <h3 className="text-lg font-bold mb-4 flex items-center text-yellow-600">
              <Pause className="w-5 h-5 mr-2" />
              Pausar Projeto
            </h3>
            <p className="text-gray-600 text-sm mb-4">
              Isso irá parar o cronômetro. O projeto ficará salvo na lista para retorno posterior.
            </p>
            <label className="block text-sm font-medium text-gray-700 mb-1">Motivo da Pausa</label>
            <input 
              type="text" 
              autoFocus
              value={pauseReason}
              onChange={e => setPauseReason(e.target.value)}
              placeholder="Ex: Almoço..."
              className="w-full p-3 border rounded-lg mb-6 focus:ring-2 focus:ring-yellow-500 outline-none"
            />
            <div className="flex justify-end gap-2">
              <button 
                onClick={() => setShowPauseModal(false)}
                className="text-gray-500 px-4 py-2 rounded-lg font-medium hover:bg-gray-100"
              >
                Cancelar
              </button>
              <button 
                onClick={confirmPauseAndExit}
                className="bg-yellow-500 text-white px-4 py-2 rounded-lg font-medium hover:bg-yellow-600"
              >
                Confirmar Pausa
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Floating Timer Pop-up */}
      {!isVisible && activeProject && (
        <div 
          onClick={onNavigateBack}
          className="fixed bottom-6 right-6 z-50 bg-slate-900 text-white p-4 rounded-xl shadow-2xl cursor-pointer hover:bg-slate-800 transition-all transform hover:scale-105 group border border-slate-700 ring-2 ring-blue-500/50"
        >
          <div className="flex items-center justify-between mb-2 gap-4">
            <div className="flex items-center text-green-400 text-xs font-bold uppercase tracking-wider animate-pulse">
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
              Em Andamento
            </div>
            <Maximize2 className="w-4 h-4 text-gray-400 group-hover:text-white" />
          </div>
          <div className="font-mono text-3xl font-bold mb-1">
            {formatTime(elapsedSeconds)}
          </div>
          <div className="text-xs text-gray-400 mb-1">
            NS: {activeProject.ns}
          </div>
          <div className="text-xs text-blue-400 font-medium mt-2 border-t border-slate-700 pt-2">
            Clique para retornar
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PenTool, AlertOctagon, Menu, X, History, Users, LogOut, Lightbulb, Shield, Activity, Eye } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { IssueHistory } from './components/IssueHistory';
import { Dashboard } from './components/Dashboard';
import { ProjectHistory } from './components/ProjectHistory';
import { UserManagement } from './components/UserManagement';
import { InnovationManager } from './components/InnovationManager';
import { Login } from './components/Login';
import { 
  fetchAppState, 
  addProject, 
  updateProject, 
  deleteProject,
  addIssue, 
  deleteIssue,
  addInnovation, 
  updateInnovationStatus,
  deleteInnovation
} from './services/storageService';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from './types';
import logoImg from './src/assets/logo.png'; 

const COMPANY_LOGO_URL = logoImg;

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); 

  // --- PERMISSIONS LOGIC ---

  // Who can see ALL project history?
  const canSeeAllHistory = useMemo(() => {
      if (!currentUser) return false;
      return ['GESTOR', 'CEO', 'PROCESSOS', 'QUALIDADE'].includes(currentUser.role);
  }, [currentUser]);

  // Who can manage Innovations? (CEO, Processes, Manager, Designer)
  const canSeeInnovations = useMemo(() => {
      if (!currentUser) return false;
      return ['GESTOR', 'CEO', 'PROCESSOS', 'PROJETISTA'].includes(currentUser.role);
  }, [currentUser]);

  // Who can see Dashboard? (Everyone)
  // Who can see Team? (Manager)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    const role = currentUser.role;

    // "Super Viewers" - See everything in DB
    if (['GESTOR', 'CEO', 'PROCESSOS'].includes(role)) {
      return data;
    }

    // QUALITY - Sees all Issues (to analyze), All Projects (for context in charts), No Innovations
    if (role === 'QUALIDADE') {
        return {
            projects: data.projects, // Needed for charts context
            issues: data.issues,
            innovations: [] // Not relevant
        };
    }

    // PROJETISTA - Sees own data + All Innovations (usually shared knowledge)
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      innovations: data.innovations
    };
  }, [data, currentUser]);

  // --- HANDLERS ---

  const handleProjectCreate = async (project: ProjectSession) => {
    const projectWithUser = { ...project, userId: currentUser?.id };
    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));
    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao criar projeto.");
    }
  };

  const handleProjectUpdate = async (project: ProjectSession) => {
    setData(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === project.id ? project : p)
    }));
    try {
        const updatedData = await updateProject(project);
        setData(updatedData);
        if (project.status === 'COMPLETED') {
             // Optional alert
        }
    } catch (e) {
        alert("Erro ao atualizar projeto.");
    }
  };

  const handleProjectDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar este projeto? Essa ação não pode ser desfeita.")) return;

    setIsLoading(true);
    try {
      const updatedData = await deleteProject(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar projeto.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };
     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));
    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar esta ocorrência?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteIssue(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar ocorrência.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    // Optimistic Update
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));

    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      console.error(e);
      alert("Erro ao salvar inovação.");
      const revertedData = await fetchAppState();
      setData(revertedData);
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleInnovationDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja excluir esta inovação?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteInnovation(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao excluir inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors border-r-4 ${
        activeTab === id 
          ? 'bg-slate-800 border-blue-500 text-blue-400 font-medium' 
          : 'border-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white shadow-xl">
        <div className="p-6 border-b border-slate-800">
          <div className="mb-6 flex items-center gap-3">
             <img 
               src={COMPANY_LOGO_URL}
               alt="Logo" 
               className="h-10 w-auto max-w-[50px] object-contain" 
             />
             <div className="flex flex-col">
                <span className="text-2xl font-bold text-white leading-none tracking-tight">
                  Project<span className="text-blue-500">Tracker</span>
                </span>
             </div>
          </div>

          <div className="flex items-center text-slate-500 text-xs mb-1 uppercase tracking-wider font-semibold">
            Painel de Controle
          </div>
          <p className="text-sm font-medium text-slate-200 truncate">{currentUser.name}</p>
          <div className="flex items-center mt-2 gap-2">
            <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 bg-slate-800 border border-slate-700 px-2 py-0.5 rounded-full inline-block">
                {currentUser.role}
            </span>
          </div>
        </div>
        <nav className="flex-1 mt-6 overflow-y-auto">
          {['PROJETISTA', 'GESTOR'].includes(currentUser.role) && (
             <NavItem id="tracker" label="Projetar" icon={PenTool} />
          )}

          <NavItem id="history" label="Histórico" icon={History} />
          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />

          {canSeeInnovations && (
             <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
          )}

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 hover:bg-slate-800/50 p-2 rounded-lg font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4 shadow-md">
        <div className="h-8 flex items-center gap-2">
            <img 
                src={COMPANY_LOGO_URL} 
                alt="Logo" 
                className="h-full w-auto object-contain"
            />
            <span className="text-lg font-bold text-white">
                Project<span className="text-blue-500">Tracker</span>
            </span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white transition-colors">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden animate-in slide-in-from-right duration-200">
          <nav className="flex flex-col h-full overflow-y-auto">
            {['PROJETISTA', 'GESTOR'].includes(currentUser.role) && (
                <NavItem id="tracker" label="Projetar" icon={PenTool} />
            )}
            <NavItem id="history" label="Histórico" icon={History} />
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            {canSeeInnovations && (
                <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            )}
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <div className="mt-auto p-6 border-t border-slate-800">
              <button 
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-3 text-left text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
              >
                <LogOut className="w-5 h-5 mr-3" />
                Sair
              </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all bg-gray-50 min-h-screen">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Área de Projeto</h2>
                <p className="text-gray-500">Bem-vindo, <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
              </div>
            </div>
            <ProjectTracker 
              existingProjects={displayData.projects}
              onCreate={handleProjectCreate}
              onUpdate={handleProjectUpdate}
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
            <div className="space-y-6">
              <div className="mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Histórico de Liberações</h2>
                <p className="text-gray-500">
                  {canSeeAllHistory
                    ? "Visão geral de todas as liberações da equipe." 
                    : "Consulte suas liberações passadas."}
                </p>
              </div>
              <ProjectHistory 
                data={displayData} 
                currentUser={currentUser} 
                onDelete={handleProjectDelete}
              />
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="space-y-6">
               <div className="mb-6 flex items-center gap-4">
                 <div className="bg-slate-900 p-2 rounded-xl shadow-sm border border-slate-800">
                    <img 
                      src={COMPANY_LOGO_URL}
                      alt="Logo" 
                      className="h-12 w-auto object-contain" 
                    />
                 </div>
                 <div>
                    <h2 className="text-2xl font-bold text-gray-800">Painel de Desempenho</h2>
                    <p className="text-gray-500">
                      {canSeeAllHistory ? "Indicadores globais da equipe." : "Seus indicadores de produtividade."}
                    </p>
                 </div>
              </div>
              <Dashboard data={displayData} currentUser={currentUser} />
            </div>
          )}

          {activeTab === 'issues' && (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                <div>
                   <h2 className="text-2xl font-bold text-gray-800">Gestão de Qualidade</h2>
                   <p className="text-gray-500">Reporte e analise os problemas ocorridos.</p>
                </div>
                <div className="bg-gray-200 p-1 rounded-lg inline-flex">
                  <button 
                    onClick={() => setIssueTab('new')}
                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'new' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Novo Registro
                  </button>
                  <button 
                    onClick={() => setIssueTab('history')}
                     className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${
                      issueTab === 'history' ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                    }`}
                  >
                    Histórico de Problemas
                  </button>
                </div>
              </div>

              {issueTab === 'new' ? (
                <IssueReporter onReport={handleIssueReport} />
              ) : (
                <IssueHistory 
                  data={displayData} 
                  currentUser={currentUser} 
                  onDelete={handleIssueDelete}
                />
              )}
            </div>
          )}

          {activeTab === 'innovations' && canSeeInnovations && (
             <InnovationManager 
                innovations={displayData.innovations} 
                onAdd={handleInnovationAdd}
                onStatusChange={handleInnovationStatusChange}
                onDelete={handleInnovationDelete}
                currentUser={currentUser}
             />
          )}

          {activeTab === 'team' && currentUser.role === 'GESTOR' && (
             <div className="space-y-6">
                <div className="mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">Gestão de Equipe</h2>
                  <p className="text-gray-500">Adicione novos membros e gerencie permissões de acesso.</p>
                </div>
                <UserManagement />
             </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { Sparkles, BarChart3, PieChart as PieIcon, Download, Clock, Filter, Truck, User as UserIcon, Lightbulb, TrendingDown } from 'lucide-react';
import { AppState, User, InnovationType } from '../types';
import { analyzePerformance } from '../services/geminiService';
import { fetchUsers } from '../services/storageService';

interface DashboardProps {
  data: AppState;
  currentUser: User;
}

const COLORS = ['#ef4444', '#f97316', '#eab308', '#3b82f6', '#8b5cf6', '#ec4899'];

export const Dashboard: React.FC<DashboardProps> = ({ data, currentUser }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);
  const [usersMap, setUsersMap] = useState<Record<string, string>>({});

  // Filter States
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const isQualityRole = currentUser.role === 'QUALIDADE';

  useEffect(() => {
    // Load users for the manager chart
    const load = async () => {
      const users = await fetchUsers();
      const map = users.reduce((acc, u) => ({ ...acc, [u.id]: u.name }), {} as Record<string, string>);
      setUsersMap(map);
    };
    load();
  }, []);

  // Filter Data Logic
  const filteredProjects = useMemo(() => {
    return data.projects.filter(p => {
      if (p.status !== 'COMPLETED') return false;

      let matchDate = true;
      if (startDate || endDate) {
        const pDate = new Date(p.endTime || p.startTime).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = pDate >= start && pDate <= end;
      }
      return matchDate;
    });
  }, [data.projects, startDate, endDate]);

  const filteredIssues = useMemo(() => {
     return data.issues.filter(i => {
      let matchDate = true;
      if (startDate || endDate) {
        const iDate = new Date(i.date).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = iDate >= start && iDate <= end;
      }
      return matchDate;
     });
  }, [data.issues, startDate, endDate]);

   const filteredInnovations = useMemo(() => {
    return data.innovations.filter(inv => {
      let matchDate = true;
      if (startDate || endDate) {
        const iDate = new Date(inv.createdAt).getTime();
        const start = startDate ? new Date(startDate).getTime() : 0;
        const end = endDate ? new Date(endDate).setHours(23, 59, 59, 999) : Infinity;
        matchDate = iDate >= start && iDate <= end;
      }
      return matchDate;
    });
  }, [data.innovations, startDate, endDate]);


  // 1. Calculate Average Time per Project Type
  const averageTimes = useMemo(() => {
    const sums: Record<string, { total: number; count: number }> = {};

    filteredProjects.forEach(p => {
      if (!sums[p.type]) sums[p.type] = { total: 0, count: 0 };
      sums[p.type].total += p.totalActiveSeconds;
      sums[p.type].count += 1;
    });

    return Object.entries(sums).map(([type, stats]) => ({
      type,
      avgSeconds: Math.round(stats.total / stats.count)
    }));
  }, [filteredProjects]);

  // 1.5 Calculate Total Savings (ONLY APPROVED/IMPLEMENTED)
  const totalSavings = useMemo(() => {
    return filteredInnovations.reduce((acc, curr) => {
        // Only count if status is APPROVED or IMPLEMENTED
        if (curr.status === 'APPROVED' || curr.status === 'IMPLEMENTED') {
            return acc + (curr.totalAnnualSavings || 0);
        }
        return acc;
    }, 0);
  }, [filteredInnovations]);

  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return `${h}h ${m}m`;
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 }).format(val);
  };

  // 2. Bar Chart Data: Releases per Month
  const barData = useMemo(() => {
    const releasesByMonth = filteredProjects
      .reduce((acc, curr) => {
        const date = new Date(curr.endTime!);
        const monthYear = date.toLocaleString('pt-BR', { month: 'short' });
        const key = monthYear.charAt(0).toUpperCase() + monthYear.slice(1);
        acc[key] = (acc[key] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);

    return Object.keys(releasesByMonth).map(key => ({
      name: key,
      liberacoes: releasesByMonth[key]
    }));
  }, [filteredProjects]);

  // 3. Pie Chart Data: Issue Type Distribution
  const pieData = useMemo(() => {
    const issuesByType = filteredIssues.reduce((acc, curr) => {
      acc[curr.type] = (acc[curr.type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(issuesByType).map(type => ({
      name: type,
      value: issuesByType[type]
    }));
  }, [filteredIssues]);

  // 4. Pie Chart: Implement Type Distribution
  const implementData = useMemo(() => {
    const counts = filteredProjects.reduce((acc, curr) => {
      const type = curr.implementType || 'Não Informado';
      acc[type] = (acc[type] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(counts).map(key => ({
      name: key,
      value: counts[key]
    }));
  }, [filteredProjects]);

  // 5. Bar Chart: Releases by Designer (Manager Only)
  const designerData = useMemo(() => {
    if (currentUser.role !== 'GESTOR') return [];

    const counts = filteredProjects.reduce((acc, curr) => {
      const name = usersMap[curr.userId || ''] || 'Desconhecido';
      acc[name] = (acc[name] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.keys(counts).map(key => ({
      name: key,
      liberacoes: counts[key]
    }));
  }, [filteredProjects, currentUser.role, usersMap]);

  // 6. Stacked Bar Chart: Innovations by Status and Type
  const innovationChartData = useMemo(() => {
    const statuses = ['PENDING', 'APPROVED', 'IMPLEMENTED', 'REJECTED'];
    const labelMap: Record<string, string> = {
        'PENDING': 'Pendente',
        'APPROVED': 'Aprovado',
        'IMPLEMENTED': 'Implementado',
        'REJECTED': 'Rejeitado'
    };

    return statuses.map(status => {
        const items = filteredInnovations.filter(i => i.status === status);
        const newProjects = items.filter(i => i.type === InnovationType.NEW_PROJECT).length;
        const improvements = items.filter(i => i.type === InnovationType.PRODUCT_IMPROVEMENT).length;
        const optimizations = items.filter(i => i.type === InnovationType.PROCESS_OPTIMIZATION).length;

        return {
            name: labelMap[status],
            "Novo Projeto": newProjects,
            "Melhoria": improvements,
            "Otimização": optimizations
        };
    });
  }, [filteredInnovations]);


  const handleAiAnalysis = async () => {
    setIsLoadingAi(true);
    const result = await analyzePerformance(filteredProjects, filteredIssues);
    setAiAnalysis(result);
    setIsLoadingAi(false);
  };

  const handleExportCSV = () => {
    const headers = ['ID', 'NS', 'Codigo', 'Tipo', 'Implemento', 'Inicio', 'Fim', 'Tempo Total(s)', 'Status', 'Notas'];
    const rows = filteredProjects.map(p => [
      p.id,
      p.ns,
      p.projectCode || '',
      p.type,
      p.implementType || '',
      p.startTime,
      p.endTime || '',
      p.totalActiveSeconds,
      p.status,
      `"${(p.notes || '').replace(/"/g, '""')}"`
    ].join(','));

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(','), ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `design_track_export_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">

      {/* Date Filter Section */}
      <div className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex items-center text-gray-700 font-bold">
          <Filter className="w-5 h-5 mr-2 text-blue-600" />
          Período de Análise
        </div>
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">De:</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>
          <div className="flex items-center gap-2">
            <span className="text-xs text-gray-500">Até:</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm"
            />
          </div>
        </div>
        {!isQualityRole && (
          <button 
            onClick={handleExportCSV}
            className="flex items-center text-sm font-medium text-gray-600 hover:text-gray-900 bg-gray-50 border border-gray-200 px-4 py-2 rounded-lg hover:bg-gray-100 transition-colors ml-auto md:ml-0"
          >
            <Download className="w-4 h-4 mr-2" />
            CSV
          </button>
        )}
      </div>

      {/* KPI Section */}
      {!isQualityRole && (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {averageTimes.length > 0 && averageTimes.map((stat) => (
            <div key={stat.type} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-1">Média {stat.type}</p>
                <p className="text-xl font-bold text-gray-800">{formatDuration(stat.avgSeconds)}</p>
              </div>
              <div className="h-8 w-8 bg-blue-50 rounded-full flex items-center justify-center text-blue-600">
                <Clock className="w-4 h-4" />
              </div>
            </div>
          ))}
          {/* Innovation KPI */}
           <div className="bg-white p-4 rounded-xl border border-emerald-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-xs font-bold text-emerald-600 uppercase tracking-wider mb-1">Economia Aprovada</p>
                <p className="text-xl font-bold text-emerald-800">{formatCurrency(totalSavings)}</p>
              </div>
              <div className="h-8 w-8 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-600">
                <TrendingDown className="w-4 h-4" />
              </div>
            </div>
        </div>
      )}

      {/* AI Insights Section */}
      {!isQualityRole && (
        <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-xl font-bold text-indigo-900 flex items-center">
              <Sparkles className="w-5 h-5 mr-2 text-indigo-600" />
              Análise Inteligente (IA)
            </h3>
            <button 
              onClick={handleAiAnalysis}
              disabled={isLoadingAi}
              className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm hover:bg-indigo-700 transition-colors disabled:opacity-50"
            >
              {isLoadingAi ? 'Analisando...' : 'Gerar Relatório'}
            </button>
          </div>

          {aiAnalysis ? (
            <div className="prose prose-sm max-w-none text-indigo-900 bg-white/50 p-4 rounded-lg">
              <pre className="whitespace-pre-wrap font-sans text-sm leading-relaxed">{aiAnalysis}</pre>
            </div>
          ) : (
            <p className="text-indigo-600/70 text-sm">
              Clique em "Gerar Relatório" para que a IA analise o desempenho do período selecionado.
            </p>
          )}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Issue Distribution (Pie Chart) - VISIBLE TO QUALITY AND OTHERS */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px] col-span-1 md:col-span-2 lg:col-span-1">
          <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
            <PieIcon className="w-5 h-5 mr-2 text-red-500" />
            Distribuição de Problemas
          </h3>
          <div className="h-[250px] w-full">
            {pieData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    outerRadius={80}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {pieData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend 
                    layout="vertical" 
                    verticalAlign="middle" 
                    align="right"
                    wrapperStyle={{ fontSize: '12px' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                Nenhum problema registrado no período.
              </div>
            )}
          </div>
        </div>

        {/* Releases per Month (Bar Chart) - HIDDEN FOR QUALITY */}
        {!isQualityRole && (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
            <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
                <BarChart3 className="w-5 h-5 mr-2 text-blue-500" />
                Liberações por Mês
            </h3>
            <div className="h-[250px] w-full">
                {barData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={barData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" tickLine={false} axisLine={false} />
                    <YAxis allowDecimals={false} tickLine={false} axisLine={false} />
                    <Tooltip cursor={{ fill: '#f3f4f6' }} />
                    <Bar dataKey="liberacoes" name="Liberações" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                    </BarChart>
                </ResponsiveContainer>
                ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                    Sem dados para exibir.
                </div>
                )}
            </div>
            </div>
        )}

        {/* Innovations Chart - HIDDEN FOR QUALITY */}
        {!isQualityRole && (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
            <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
                <Lightbulb className="w-5 h-5 mr-2 text-yellow-500" />
                Status de Inovações
            </h3>
            <div className="h-[250px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={innovationChartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" tickLine={false} axisLine={false} style={{fontSize: '12px'}} />
                        <YAxis allowDecimals={false} tickLine={false} axisLine={false} />
                        <Tooltip cursor={{ fill: '#f3f4f6' }} />
                        <Legend />
                        <Bar dataKey="Novo Projeto" stackId="a" fill="#8b5cf6" />
                        <Bar dataKey="Melhoria" stackId="a" fill="#3b82f6" />
                        <Bar dataKey="Otimização" stackId="a" fill="#f97316" />
                    </BarChart>
                </ResponsiveContainer>
            </div>
            </div>
        )}

        {/* Implement Type (Pie Chart) - HIDDEN FOR QUALITY */}
        {!isQualityRole && (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
            <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
                <Truck className="w-5 h-5 mr-2 text-orange-500" />
                Distribuição por Implemento
            </h3>
            <div className="h-[250px] w-full">
                {implementData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                    <Pie
                        data={implementData}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        outerRadius={80}
                        fill="#8884d8"
                        dataKey="value"
                    >
                        {implementData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip />
                    <Legend 
                        layout="vertical" 
                        verticalAlign="middle" 
                        align="right"
                        wrapperStyle={{ fontSize: '12px' }}
                    />
                    </PieChart>
                </ResponsiveContainer>
                ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                    Sem dados para exibir.
                </div>
                )}
            </div>
            </div>
        )}

        {/* Manager Only: Releases by Designer */}
        {currentUser.role === 'GESTOR' && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 min-h-[350px]">
            <h3 className="text-lg font-bold text-gray-700 mb-4 flex items-center">
              <UserIcon className="w-5 h-5 mr-2 text-purple-600" />
              Liberações por Projetista
            </h3>
             <div className="h-[250px] w-full">
              {designerData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={designerData} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                    <XAxis type="number" allowDecimals={false} tickLine={false} axisLine={false} />
                    <YAxis dataKey="name" type="category" width={100} tickLine={false} axisLine={false} />
                    <Tooltip cursor={{ fill: '#f3f4f6' }} />
                    <Bar dataKey="liberacoes" name="Projetos" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={20} />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                  Sem dados para exibir.
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export enum ProjectType {
  VARIATION = 'Variação',
  DEVELOPMENT = 'Desenvolvimento',
  RELEASE = 'Liberação'
}

export enum ImplementType {
  BASE = 'Base',
  FURGAO = 'Furgão',
  SIDER = 'Sider',
  CAIXA_CARGA = 'Caixa de Carga',
  BASCULANTE = 'Basculante',
  COMPONENTES = 'Componentes',
  OUTROS = 'Outros'
}

export enum IssueType {
  DESIGN_ERROR = 'Erro de Projeto',
  BENDING_ERROR = 'Erro de Dobra',
  CUTTING_ERROR = 'Erro de Corte',
  MATERIAL_ERROR = 'Erro de Material',
  ASSEMBLY_ERROR = 'Erro de Montagem'
}

export enum InnovationType {
  NEW_PROJECT = 'Novo Projeto',
  PRODUCT_IMPROVEMENT = 'Melhoria de Produto',
  PROCESS_OPTIMIZATION = 'Otimização de Processo'
}

export enum CalculationType {
  PER_UNIT = 'Por Unidade Produzida',
  RECURRING_MONTHLY = 'Recorrente (Mensal)',
  ONE_TIME = 'Valor Único / Fixo'
}

export type UserRole = 'GESTOR' | 'PROJETISTA' | 'CEO' | 'QUALIDADE' | 'PROCESSOS';

export interface User {
  id: string;
  username: string;
  password: string; // In a real app, this should be hashed. Storing plain for local prototype.
  name: string;
  role: UserRole;
}

export interface PauseRecord {
  reason: string;
  timestamp: string; // ISO string
  durationSeconds: number; // Approximate duration of this pause
}

export interface VariationRecord {
  id: string;
  oldCode: string;
  description: string;
  newCode: string;
  type: 'Montagem' | 'Peça';
  filesGenerated: boolean; // DXF/PDF check
}

export interface ProjectSession {
  id: string;
  ns: string;
  clientName?: string; // New
  flooringType?: string; // New
  projectCode?: string;
  type: ProjectType;
  implementType?: ImplementType;
  startTime: string; // ISO
  endTime?: string; // ISO
  totalActiveSeconds: number;
  pauses: PauseRecord[];
  variations: VariationRecord[]; // New
  status: 'COMPLETED' | 'IN_PROGRESS';
  notes?: string;
  userId?: string; // Track who did this project
}

export interface IssueRecord {
  id: string;
  projectNs: string;
  type: IssueType;
  description: string;
  date: string;
  reportedBy?: string; // Track who reported
}

export interface InnovationRecord {
  id: string;
  title: string;
  description: string;
  type: InnovationType;

  // Advanced Calculation Fields
  calculationType: CalculationType;
  unitSavings: number; // The base value (e.g., saving per unit, or value per month)
  quantity: number; // Multiplier (e.g., units per year, or 12 months)
  totalAnnualSavings: number; // The calculated total: unitSavings * quantity (if recurring/unit)
  investmentCost?: number; // Cost to implement (optional)

  status: 'PENDING' | 'APPROVED' | 'REJECTED' | 'IMPLEMENTED';
  authorId?: string;
  createdAt: string;
}

export interface AppState {
  projects: ProjectSession[];
  issues: IssueRecord[];
  innovations: InnovationRecord[];
}

import React, { useState, useEffect } from 'react';
import { UserPlus, Shield, User as UserIcon, CheckCircle, Loader2, Eye, Activity, Briefcase } from 'lucide-react';
import { User, UserRole } from '../types';
import { registerUser, fetchUsers } from '../services/storageService';

export const UserManagement: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [loadingList, setLoadingList] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState<UserRole>('PROJETISTA');
  const [successMsg, setSuccessMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);

  useEffect(() => {
    loadList();
  }, []);

  const loadList = async () => {
    setLoadingList(true);
    const list = await fetchUsers();
    setUsers(list);
    setLoadingList(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg('');
    setSuccessMsg('');
    setIsRegistering(true);

    const newUser: User = {
      id: crypto.randomUUID(),
      name,
      username,
      password,
      role
    };

    const success = await registerUser(newUser);
    if (success) {
      setSuccessMsg(`Usuário ${name} criado com sucesso!`);
      await loadList(); // Refresh list
      // Reset form
      setName('');
      setUsername('');
      setPassword('');
    } else {
      setErrorMsg('Erro ao criar usuário. Verifique se o nome de usuário já existe.');
    }
    setIsRegistering(false);
  };

  const getRoleIcon = (role: UserRole) => {
      switch(role) {
          case 'GESTOR': return <Shield className="w-3 h-3 text-blue-600" />;
          case 'CEO': return <Briefcase className="w-3 h-3 text-yellow-600" />;
          case 'PROCESSOS': return <Activity className="w-3 h-3 text-purple-600" />;
          case 'QUALIDADE': return <Eye className="w-3 h-3 text-red-600" />;
          default: return <UserIcon className="w-3 h-3 text-gray-600" />;
      }
  };

  return (
    <div className="space-y-6">
      {/* Create User Form */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold mb-6 flex items-center text-gray-800">
          <UserPlus className="w-6 h-6 mr-2 text-indigo-600" />
          Cadastrar Novo Usuário
        </h2>

        {successMsg && (
          <div className="mb-4 p-3 bg-green-50 text-green-700 rounded-lg flex items-center">
            <CheckCircle className="w-4 h-4 mr-2" /> {successMsg}
          </div>
        )}

        {errorMsg && (
          <div className="mb-4 p-3 bg-red-50 text-red-700 rounded-lg">
            {errorMsg}
          </div>
        )}

        <form onSubmit={handleRegister} className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
            <input 
              type="text" 
              value={name}
              onChange={e => setName(e.target.value)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nome de Usuário (Login)</label>
            <input 
              type="text" 
              value={username}
              onChange={e => setUsername(e.target.value)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Senha</label>
            <input 
              type="text" // Visible for ease of creation
              value={password}
              onChange={e => setPassword(e.target.value)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              placeholder="Defina uma senha"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Função</label>
            <select 
              value={role}
              onChange={e => setRole(e.target.value as UserRole)}
              className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              <option value="PROJETISTA">Projetista</option>
              <option value="GESTOR">Gestor</option>
              <option value="CEO">CEO</option>
              <option value="PROCESSOS">Processos</option>
              <option value="QUALIDADE">Qualidade</option>
            </select>
          </div>
          <div className="md:col-span-2">
            <button 
              type="submit"
              disabled={isRegistering}
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2 rounded-lg transition-colors flex items-center justify-center"
            >
              {isRegistering ? <Loader2 className="w-5 h-5 animate-spin mr-2" /> : null}
              {isRegistering ? 'Cadastrando...' : 'Cadastrar'}
            </button>
          </div>
        </form>
      </div>

      {/* Users List */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
           <h3 className="font-bold text-gray-700">Membros da Equipe</h3>
           {loadingList && <Loader2 className="w-4 h-4 text-gray-400 animate-spin" />}
        </div>
        <table className="w-full text-sm text-left">
          <thead className="bg-gray-50 text-gray-600 font-medium">
            <tr>
              <th className="p-4">Nome</th>
              <th className="p-4">Usuário</th>
              <th className="p-4">Função</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {users.map((u) => (
              <tr key={u.id} className="hover:bg-gray-50">
                <td className="p-4 font-medium text-gray-800 flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-gray-200 flex items-center justify-center text-gray-500 font-bold">
                    {u.name.charAt(0)}
                  </div>
                  {u.name}
                </td>
                <td className="p-4 text-gray-600">{u.username}</td>
                <td className="p-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-bold flex items-center w-fit gap-1 bg-gray-100 text-gray-700`}>
                    {getRoleIcon(u.role)}
                    {u.role}
                  </span>
                </td>
              </tr>
            ))}
            {!loadingList && users.length === 0 && (
              <tr>
                <td colSpan={3} className="p-4 text-center text-gray-400">Nenhum usuário encontrado.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Square, Clock, AlertCircle, Timer, Hash, Truck, Maximize2, Briefcase, ChevronRight, Plus, FileCheck, FileX, Trash2, Building, Layers, CheckSquare, Edit3 } from 'lucide-react';
import { ProjectType, ProjectSession, PauseRecord, ImplementType, VariationRecord } from '../types';
import { PROJECT_TYPES, IMPLEMENT_TYPES, FLOORING_TYPES } from '../constants';

// SUBSTITUA ISSO PELA SUA URL DO WEBHOOK DO TEAMS
const TEAMS_WEBHOOK_URL = "https://outlook.office.com/webhook/YOUR_WEBHOOK_URL_HERE";

interface ProjectTrackerProps {
  existingProjects: ProjectSession[];
  onCreate: (project: ProjectSession) => void;
  onUpdate: (project: ProjectSession) => void;
  isVisible: boolean;
  onNavigateBack: () => void;
}

export const ProjectTracker: React.FC<ProjectTrackerProps> = ({ existingProjects, onCreate, onUpdate, isVisible, onNavigateBack }) => {
  const [activeProject, setActiveProject] = useState<ProjectSession | null>(null);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);

  // Form Data (Start)
  const [ns, setNs] = useState('');
  const [clientName, setClientName] = useState('');
  const [projectCode, setProjectCode] = useState('');
  const [type, setType] = useState<ProjectType>(ProjectType.RELEASE);
  const [implementType, setImplementType] = useState<ImplementType>(ImplementType.BASE);
  const [flooringType, setFlooringType] = useState('');
  const [notes, setNotes] = useState('');

  // Variation Form Data
  const [varOldCode, setVarOldCode] = useState('');
  const [varNewCode, setVarNewCode] = useState('');
  const [varDesc, setVarDesc] = useState('');
  const [varType, setVarType] = useState<'Montagem' | 'Peça'>('Peça');
  const [varFiles, setVarFiles] = useState(false);

  // Pause Logic
  const [showPauseModal, setShowPauseModal] = useState(false);
  const [pauseReason, setPauseReason] = useState('');

  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const pendingProjects = existingProjects.filter(p => p.status === 'IN_PROGRESS');

  // Helper to check if flooring field should show
  const shouldShowFlooring = ['Base', 'Furgão', 'Sider'].includes(implementType);

  useEffect(() => {
    const updateTimer = () => {
      if (!activeProject) {
        setElapsedSeconds(0);
        return;
      }
      const now = Date.now();
      const start = new Date(activeProject.startTime).getTime();
      const diffTotal = Math.floor((now - start) / 1000);
      const totalClosedPauses = activeProject.pauses.reduce((acc, p) => acc + p.durationSeconds, 0);
      setElapsedSeconds(Math.max(0, diffTotal - totalClosedPauses));
    };

    if (activeProject && !showPauseModal) {
      updateTimer();
      timerRef.current = setInterval(updateTimer, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [activeProject, showPauseModal]);


  const handleStartNew = () => {
    if (!ns.trim()) {
      alert("Por favor, informe o NS do projeto antes de começar.");
      return;
    }

    const newProject: ProjectSession = {
      id: crypto.randomUUID(),
      ns,
      clientName,
      projectCode,
      type,
      implementType,
      flooringType: shouldShowFlooring ? flooringType : undefined,
      startTime: new Date().toISOString(),
      totalActiveSeconds: 0,
      pauses: [],
      variations: [], // Start empty
      status: 'IN_PROGRESS',
      notes
    };

    onCreate(newProject);
    setActiveProject(newProject);

    // Reset form fields
    setNs('');
    setClientName('');
    setProjectCode('');
    setNotes('');
    setFlooringType('');
  };

  const handleResumeFromList = (project: ProjectSession) => {
    // Logic to close open pause if needed
    const lastPauseIndex = project.pauses.length - 1;
    if (lastPauseIndex >= 0 && project.pauses[lastPauseIndex].durationSeconds === -1) {
       const pauseStart = new Date(project.pauses[lastPauseIndex].timestamp).getTime();
       const now = Date.now();
       const duration = Math.floor((now - pauseStart) / 1000);

       const updatedPauses = [...project.pauses];
       updatedPauses[lastPauseIndex] = {
         ...updatedPauses[lastPauseIndex],
         durationSeconds: duration
       };

       const updatedProject = { ...project, pauses: updatedPauses };
       onUpdate(updatedProject);
       setActiveProject(updatedProject);
    } else {
       setActiveProject(project);
    }
  };

  const handlePauseProject = () => setShowPauseModal(true);

  const confirmPauseAndExit = () => {
    if (!activeProject) return;

    const newPause: PauseRecord = {
      reason: pauseReason || 'Pausa',
      timestamp: new Date().toISOString(),
      durationSeconds: -1 // Flag for "Open/Ongoing" pause
    };

    const updatedProject = {
      ...activeProject,
      pauses: [...activeProject.pauses, newPause]
    };

    onUpdate(updatedProject);
    setActiveProject(null);
    setShowPauseModal(false);
    setPauseReason('');
  };

  const handleFinish = async () => {
    if (!activeProject) return;

    const now = Date.now();
    const start = new Date(activeProject.startTime).getTime();
    const totalClosedPauses = activeProject.pauses.reduce((acc, p) => acc + (p.durationSeconds > 0 ? p.durationSeconds : 0), 0);
    const finalSeconds = Math.floor((now - start) / 1000) - totalClosedPauses;

    const finishedProject: ProjectSession = {
      ...activeProject,
      endTime: new Date().toISOString(),
      totalActiveSeconds: finalSeconds,
      status: 'COMPLETED'
    };

    onUpdate(finishedProject);
    sendTeamsNotification(finishedProject);
    setActiveProject(null);
  };

  // --- VARIATION HANDLERS ---
  const handleAddVariation = () => {
      if (!activeProject) return;
      if (!varOldCode.trim() && !varNewCode.trim()) {
          alert("Insira pelo menos um código (antigo ou novo).");
          return;
      }

      const newVar: VariationRecord = {
          id: crypto.randomUUID(),
          oldCode: varOldCode,
          newCode: varNewCode,
          description: varDesc,
          type: varType,
          filesGenerated: varFiles
      };

      const updatedProject = {
          ...activeProject,
          variations: [...activeProject.variations, newVar]
      };

      // Optimistic update local
      setActiveProject(updatedProject);
      // Save to DB
      onUpdate(updatedProject);

      // Clear small form
      setVarOldCode('');
      setVarNewCode('');
      setVarDesc('');
      setVarFiles(false);
  };

  const handleToggleVariationFiles = (id: string) => {
      if (!activeProject) return;

      const updatedVariations = activeProject.variations.map(v => 
        v.id === id ? { ...v, filesGenerated: !v.filesGenerated } : v
      );

      const updatedProject = {
          ...activeProject,
          variations: updatedVariations
      };

      setActiveProject(updatedProject);
      onUpdate(updatedProject);
  };

  const handleDeleteVariation = (id: string) => {
      if (!activeProject) return;
      const updatedProject = {
          ...activeProject,
          variations: activeProject.variations.filter(v => v.id !== id)
      };
      setActiveProject(updatedProject);
      onUpdate(updatedProject);
  };

  const handleUpdateActiveProjectCode = (newCode: string) => {
      if (!activeProject) return;
      const updated = { ...activeProject, projectCode: newCode };
      setActiveProject(updated);
  };

  const saveProjectCode = () => {
      if (!activeProject) return;
      onUpdate(activeProject);
  };

  const sendTeamsNotification = async (project: ProjectSession) => {
    if (!TEAMS_WEBHOOK_URL || TEAMS_WEBHOOK_URL.includes("YOUR_WEBHOOK_URL_HERE")) return;

    const duration = formatTime(project.totalActiveSeconds);
    const message = {
      "@type": "MessageCard",
      "@context": "http://schema.org/extensions",
      "themeColor": "0076D7",
      "summary": "Projeto Finalizado",
      "sections": [{
        "activityTitle": "✅ Projeto Finalizado",
        "activitySubtitle": `DesignTrack Pro`,
        "facts": [
          { "name": "NS:", "value": project.ns },
          { "name": "Cliente:", "value": project.clientName || "-" },
          { "name": "Tipo:", "value": project.type },
          { "name": "Variações:", "value": project.variations.length.toString() },
          { "name": "Duração:", "value": duration }
        ],
        "markdown": true
      }]
    };

    try {
      await fetch(TEAMS_WEBHOOK_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(message)
      });
    } catch (error) {
      console.error("Erro Teams", error);
    }
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <>
      {!activeProject && (
        <div className="space-y-8">

          {/* Pending Projects */}
          {pendingProjects.length > 0 && (
            <div className="bg-white p-6 rounded-xl shadow-sm border border-blue-100">
               <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                 <Briefcase className="w-5 h-5 mr-2 text-blue-600" />
                 Projetos em Andamento / Pausados
               </h3>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 {pendingProjects.map(p => {
                    const isPaused = p.pauses.length > 0 && p.pauses[p.pauses.length - 1].durationSeconds === -1;
                    return (
                     <div key={p.id} className="border border-gray-200 rounded-lg p-4 hover:border-blue-300 transition-all bg-gray-50 group">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <div className="font-bold text-gray-800 text-lg">{p.ns}</div>
                            <div className="text-sm text-gray-500">{p.clientName}</div>
                            <div className="text-xs text-gray-400 mt-1">{p.type} • {p.implementType}</div>
                          </div>
                          <span className={`px-2 py-1 rounded text-xs font-bold ${isPaused ? 'bg-yellow-100 text-yellow-700' : 'bg-green-100 text-green-700'}`}>
                             {isPaused ? 'PAUSADO' : 'ABERTO'}
                          </span>
                        </div>
                        <button 
                          onClick={() => handleResumeFromList(p)}
                          className="w-full bg-white border border-blue-200 text-blue-600 font-bold py-2 rounded hover:bg-blue-50 transition-colors flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white shadow-sm mt-2"
                        >
                          <Play className="w-4 h-4 mr-2" />
                          {isPaused ? 'Retomar Timer' : 'Continuar'}
                        </button>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}

          {/* New Project Form */}
          <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
            <h2 className="text-xl font-bold mb-4 flex items-center text-gray-800">
              <Clock className="w-6 h-6 mr-2 text-blue-600" />
              Iniciar Novo Projeto
            </h2>
            <div className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">NS do Produto</label>
                  <input 
                    type="text" 
                    value={ns}
                    onChange={e => setNs(e.target.value)}
                    className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    placeholder="Ex: 123456"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Cliente</label>
                  <div className="relative">
                    <Building className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input 
                      type="text" 
                      value={clientName}
                      onChange={e => setClientName(e.target.value)}
                      className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      placeholder="Nome do Cliente"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Cód. Projeto (Opcional)</label>
                  <div className="relative">
                    <Hash className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <input 
                      type="text" 
                      value={projectCode}
                      onChange={e => setProjectCode(e.target.value)}
                      className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                      placeholder="Ex: PRJ-001"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Projeto</label>
                  <select 
                    value={type}
                    onChange={e => setType(e.target.value as ProjectType)}
                    className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {PROJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Implemento</label>
                  <div className="relative">
                    <Truck className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                    <select 
                      value={implementType}
                      onChange={e => setImplementType(e.target.value as ImplementType)}
                      className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    >
                      {IMPLEMENT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                  </div>
                </div>

                {shouldShowFlooring && (
                    <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Tipo de Assoalho</label>
                    <div className="relative">
                        <Layers className="absolute left-2 top-2.5 w-4 h-4 text-gray-400" />
                        <select 
                        value={flooringType}
                        onChange={e => setFlooringType(e.target.value)}
                        className="w-full pl-8 p-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                        >
                            <option value="">Selecione...</option>
                            {FLOORING_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>
                    </div>
                )}
              </div>
              <button 
                onClick={handleStartNew}
                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors"
              >
                <Play className="w-5 h-5 mr-2" />
                Começar Cronômetro
              </button>
            </div>
          </div>
        </div>
      )}

      {activeProject && (
        <div className="space-y-6">
            {/* Main Tracker Card */}
            <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 relative">
                <div className="flex justify-between items-start mb-6">
                    <h2 className="text-xl font-bold flex items-center text-gray-800">
                        <Clock className="w-6 h-6 mr-2 text-blue-600" />
                        Rastreador Ativo
                    </h2>
                    <div className="text-right">
                        <div className="font-bold text-lg text-gray-700">{activeProject.ns}</div>
                        <div className="text-xs text-gray-500 font-semibold">{activeProject.clientName}</div>
                        <div className="text-xs text-gray-400 flex flex-col items-end mt-1">
                            <span>{activeProject.implementType} {activeProject.flooringType ? `• ${activeProject.flooringType}` : ''}</span>
                            <div className="mt-1 flex items-center">
                                <span className="mr-1 text-gray-500">Cod:</span>
                                <input 
                                    type="text" 
                                    value={activeProject.projectCode || ''}
                                    onChange={(e) => handleUpdateActiveProjectCode(e.target.value)}
                                    onBlur={saveProjectCode}
                                    placeholder="Inserir Código"
                                    className="border-b border-gray-300 text-right text-xs focus:border-blue-500 focus:outline-none w-24 bg-transparent"
                                />
                                <Edit3 className="w-3 h-3 ml-1 text-gray-400" />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex flex-col items-center justify-center bg-gray-50 p-8 rounded-xl border border-gray-200 mb-6">
                    <span className="text-sm text-gray-500 font-medium tracking-wider uppercase mb-2 flex items-center animate-pulse">
                        <div className="w-2 h-2 rounded-full bg-green-500 mr-2"></div>
                        Executando
                    </span>
                    <div className="text-7xl font-mono font-bold text-blue-600 tracking-tight">
                        {formatTime(elapsedSeconds)}
                    </div>
                    <div className="mt-4 flex gap-4 text-sm text-gray-500">
                        <span>Início: {new Date(activeProject.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handlePauseProject}
                        className="bg-yellow-500 hover:bg-yellow-600 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors shadow-sm"
                    >
                        <Pause className="w-5 h-5 mr-2" />
                        Pausar / Trocar Projeto
                    </button>

                    <button 
                        onClick={handleFinish}
                        className="bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-lg flex items-center justify-center transition-colors shadow-sm"
                    >
                        <Square className="w-5 h-5 mr-2 fill-current" />
                        Finalizar Projeto
                    </button>
                </div>
            </div>

            {/* VARIATION MANAGEMENT SECTION */}
            <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100">
                 <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center border-b pb-2">
                    <Layers className="w-5 h-5 mr-2 text-purple-600" />
                    Lista de Variações de Projeto
                 </h3>

                 {/* Input Row */}
                 <div className="grid grid-cols-1 md:grid-cols-12 gap-2 mb-4 bg-gray-50 p-3 rounded-lg items-end">
                     <div className="md:col-span-2">
                        <label className="text-xs font-semibold text-gray-500">Cód. Antigo</label>
                        <input 
                            type="text" 
                            value={varOldCode}
                            onChange={e => setVarOldCode(e.target.value)}
                            className="w-full p-2 text-sm border rounded focus:ring-1 focus:ring-purple-500"
                        />
                     </div>
                     <div className="md:col-span-4">
                        <label className="text-xs font-semibold text-gray-500">Descrição / Nome</label>
                        <input 
                            type="text" 
                            value={varDesc}
                            onChange={e => setVarDesc(e.target.value)}
                            className="w-full p-2 text-sm border rounded focus:ring-1 focus:ring-purple-500"
                        />
                     </div>
                     <div className="md:col-span-2">
                        <label className="text-xs font-semibold text-gray-500">Cód. Novo</label>
                        <input 
                            type="text" 
                            value={varNewCode}
                            onChange={e => setVarNewCode(e.target.value)}
                            className="w-full p-2 text-sm border rounded focus:ring-1 focus:ring-purple-500"
                        />
                     </div>
                     <div className="md:col-span-2">
                        <label className="text-xs font-semibold text-gray-500">Tipo</label>
                        <select 
                            value={varType}
                            onChange={e => setVarType(e.target.value as any)}
                            className="w-full p-2 text-sm border rounded focus:ring-1 focus:ring-purple-500"
                        >
                            <option value="Peça">Peça</option>
                            <option value="Montagem">Montagem</option>
                        </select>
                     </div>
                     <div className="md:col-span-1 flex items-center justify-center pb-2">
                         <label className="flex items-center cursor-pointer" title="Marcar como já feito?">
                             <input 
                                type="checkbox" 
                                checked={varFiles}
                                onChange={e => setVarFiles(e.target.checked)}
                                className="w-4 h-4 text-purple-600 rounded mr-1"
                             />
                             <span className="text-xs font-bold text-gray-600">Ok</span>
                         </label>
                     </div>
                     <div className="md:col-span-1">
                         <button 
                            onClick={handleAddVariation}
                            className="w-full bg-purple-600 hover:bg-purple-700 text-white p-2 rounded flex items-center justify-center"
                         >
                             <Plus className="w-5 h-5" />
                         </button>
                     </div>
                 </div>

                 {/* Table */}
                 <div className="overflow-x-auto">
                     <table className="w-full text-sm text-left">
                         <thead className="bg-gray-100 text-gray-600 font-semibold">
                             <tr>
                                 <th className="p-3 rounded-tl-lg">Código Antigo</th>
                                 <th className="p-3">Descrição</th>
                                 <th className="p-3">Código Novo</th>
                                 <th className="p-3">Tipo</th>
                                 <th className="p-3 text-center">DXF/PDF</th>
                                 <th className="p-3 rounded-tr-lg"></th>
                             </tr>
                         </thead>
                         <tbody className="divide-y divide-gray-100">
                             {activeProject.variations.map((v) => (
                                 <tr key={v.id} className="hover:bg-gray-50">
                                     <td className="p-3 font-mono text-gray-600">{v.oldCode || '-'}</td>
                                     <td className="p-3 text-gray-800 font-medium">{v.description}</td>
                                     <td className="p-3 font-mono text-blue-600 font-bold">{v.newCode || '-'}</td>
                                     <td className="p-3">
                                         <span className={`px-2 py-0.5 rounded text-xs ${v.type === 'Montagem' ? 'bg-orange-100 text-orange-700' : 'bg-gray-200 text-gray-700'}`}>
                                             {v.type}
                                         </span>
                                     </td>
                                     <td className="p-3 text-center">
                                         <button 
                                            onClick={() => handleToggleVariationFiles(v.id)}
                                            title={v.filesGenerated ? "Arquivos Gerados (Clique para desfazer)" : "Marcar arquivos como gerados"}
                                            className={`flex items-center justify-center p-2 rounded mx-auto transition-colors ${
                                                v.filesGenerated 
                                                ? 'bg-green-100 text-green-600 hover:bg-green-200 shadow-sm' 
                                                : 'bg-gray-100 text-gray-400 hover:bg-gray-200'
                                            }`}
                                         >
                                            {v.filesGenerated ? <FileCheck className="w-4 h-4" /> : <Square className="w-4 h-4" />}
                                            <span className="ml-1 text-xs font-bold">{v.filesGenerated ? 'OK' : 'Pendente'}</span>
                                         </button>
                                     </td>
                                     <td className="p-3 text-right">
                                         <button 
                                            onClick={() => handleDeleteVariation(v.id)}
                                            className="text-gray-400 hover:text-red-500"
                                         >
                                             <Trash2 className="w-4 h-4" />
                                         </button>
                                     </td>
                                 </tr>
                             ))}
                             {activeProject.variations.length === 0 && (
                                 <tr>
                                     <td colSpan={6} className="p-6 text-center text-gray-400 italic">
                                         Nenhuma variação registrada para este projeto ainda.
                                     </td>
                                 </tr>
                             )}
                         </tbody>
                     </table>
                 </div>
            </div>
        </div>
      )}

      {/* Pause Modal */}
      {showPauseModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white p-6 rounded-xl shadow-2xl w-full max-w-md animate-in fade-in zoom-in duration-200">
            <h3 className="text-lg font-bold mb-4 flex items-center text-yellow-600">
              <Pause className="w-5 h-5 mr-2" />
              Pausar Projeto
            </h3>
            <p className="text-gray-600 text-sm mb-4">
              Isso irá parar o cronômetro. O projeto ficará salvo na lista para retorno posterior.
            </p>
            <label className="block text-sm font-medium text-gray-700 mb-1">Motivo da Pausa</label>
            <input 
              type="text" 
              autoFocus
              value={pauseReason}
              onChange={e => setPauseReason(e.target.value)}
              placeholder="Ex: Almoço..."
              className="w-full p-3 border rounded-lg mb-6 focus:ring-2 focus:ring-yellow-500 outline-none"
            />
            <div className="flex justify-end gap-2">
              <button 
                onClick={() => setShowPauseModal(false)}
                className="text-gray-500 px-4 py-2 rounded-lg font-medium hover:bg-gray-100"
              >
                Cancelar
              </button>
              <button 
                onClick={confirmPauseAndExit}
                className="bg-yellow-500 text-white px-4 py-2 rounded-lg font-medium hover:bg-yellow-600"
              >
                Confirmar Pausa
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Floating Timer Pop-up */}
      {!isVisible && activeProject && (
        <div 
          onClick={onNavigateBack}
          className="fixed bottom-6 right-6 z-50 bg-slate-900 text-white p-4 rounded-xl shadow-2xl cursor-pointer hover:bg-slate-800 transition-all transform hover:scale-105 group border border-slate-700 ring-2 ring-blue-500/50"
        >
          <div className="flex items-center justify-between mb-2 gap-4">
            <div className="flex items-center text-green-400 text-xs font-bold uppercase tracking-wider animate-pulse">
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
              Em Andamento
            </div>
            <Maximize2 className="w-4 h-4 text-gray-400 group-hover:text-white" />
          </div>
          <div className="font-mono text-3xl font-bold mb-1">
            {formatTime(elapsedSeconds)}
          </div>
          <div className="text-xs text-gray-400 mb-1">
            NS: {activeProject.ns}
          </div>
          <div className="text-xs text-blue-400 font-medium mt-2 border-t border-slate-700 pt-2">
            Clique para retornar
          </div>
        </div>
      )}
    </>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, PenTool, AlertOctagon, Menu, X, History, Users, LogOut, Lightbulb, Shield, Activity, Eye } from 'lucide-react';
import { ProjectTracker } from './components/ProjectTracker';
import { IssueReporter } from './components/IssueReporter';
import { IssueHistory } from './components/IssueHistory';
import { Dashboard } from './components/Dashboard';
import { ProjectHistory } from './components/ProjectHistory';
import { UserManagement } from './components/UserManagement';
import { InnovationManager } from './components/InnovationManager';
import { Login } from './components/Login';
import { 
  fetchAppState, 
  addProject, 
  updateProject, 
  deleteProject,
  addIssue, 
  deleteIssue,
  addInnovation, 
  updateInnovationStatus,
  deleteInnovation
} from './services/storageService';
import { AppState, ProjectSession, IssueRecord, User, InnovationRecord } from './types';
import logoImg from './src/assets/logo.png'; 

const COMPANY_LOGO_URL = logoImg;

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // App State
  const [activeTab, setActiveTab] = useState<'dashboard' | 'tracker' | 'issues' | 'history' | 'team' | 'innovations'>('tracker');
  const [issueTab, setIssueTab] = useState<'new' | 'history'>('new');
  const [data, setData] = useState<AppState>({ projects: [], issues: [], innovations: [] });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load data when user logs in or mounts
  useEffect(() => {
    const load = async () => {
      setIsLoading(true);
      const appData = await fetchAppState();
      setData(appData);
      setIsLoading(false);
    };
    load();
  }, [currentUser]); 

  // --- PERMISSIONS LOGIC ---

  // Who can see ALL project history?
  const canSeeAllHistory = useMemo(() => {
      if (!currentUser) return false;
      return ['GESTOR', 'CEO', 'PROCESSOS', 'QUALIDADE'].includes(currentUser.role);
  }, [currentUser]);

  // Who can manage Innovations? (CEO, Processes, Manager, Designer)
  const canSeeInnovations = useMemo(() => {
      if (!currentUser) return false;
      return ['GESTOR', 'CEO', 'PROCESSOS', 'PROJETISTA'].includes(currentUser.role);
  }, [currentUser]);

  // Who can see Dashboard? (Everyone)
  // Who can see Team? (Manager)

  // Filter Data based on User Role
  const displayData = useMemo(() => {
    if (!currentUser) return { projects: [], issues: [], innovations: [] };

    const role = currentUser.role;

    // "Super Viewers" - See everything in DB
    if (['GESTOR', 'CEO', 'PROCESSOS'].includes(role)) {
      return data;
    }

    // QUALITY - Sees all Issues (to analyze), All Projects (for context in charts), No Innovations
    if (role === 'QUALIDADE') {
        return {
            projects: data.projects, // Needed for charts context
            issues: data.issues,
            innovations: [] // Not relevant
        };
    }

    // PROJETISTA - Sees own data + All Innovations (usually shared knowledge)
    return {
      projects: data.projects.filter(p => p.userId === currentUser.id),
      issues: data.issues.filter(i => i.reportedBy === currentUser.id),
      innovations: data.innovations
    };
  }, [data, currentUser]);

  // --- HANDLERS ---

  const handleProjectCreate = async (project: ProjectSession) => {
    const projectWithUser = { ...project, userId: currentUser?.id };
    setData(prev => ({
      ...prev,
      projects: [projectWithUser, ...prev.projects]
    }));
    try {
      const updatedData = await addProject(projectWithUser);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao criar projeto.");
    }
  };

  const handleProjectUpdate = async (project: ProjectSession) => {
    setData(prev => ({
        ...prev,
        projects: prev.projects.map(p => p.id === project.id ? project : p)
    }));
    try {
        const updatedData = await updateProject(project);
        setData(updatedData);
        if (project.status === 'COMPLETED') {
             // Optional alert
        }
    } catch (e) {
        alert("Erro ao atualizar projeto.");
    }
  };

  const handleProjectDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar este projeto? Essa ação não pode ser desfeita.")) return;

    setIsLoading(true);
    try {
      const updatedData = await deleteProject(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar projeto.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueReport = async (issue: IssueRecord) => {
    setIsLoading(true);
    const issueWithUser = { ...issue, reportedBy: currentUser?.id };
     setData(prev => ({
      ...prev,
      issues: [issueWithUser, ...prev.issues]
    }));
    try {
      const updatedData = await addIssue(issueWithUser);
      setData(updatedData);
      alert('Problema registrado com sucesso.');
      setIssueTab('history');
    } catch (e) {
      alert("Erro ao salvar problema.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleIssueDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja apagar esta ocorrência?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteIssue(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao apagar ocorrência.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationAdd = async (innovation: InnovationRecord) => {
    setIsLoading(true);
    // Optimistic Update
    setData(prev => ({
      ...prev,
      innovations: [innovation, ...prev.innovations]
    }));

    try {
      const updatedData = await addInnovation(innovation);
      setData(updatedData);
      alert('Inovação registrada com sucesso!');
    } catch (e) {
      console.error(e);
      alert("Erro ao salvar inovação.");
      const revertedData = await fetchAppState();
      setData(revertedData);
    } finally {
      setIsLoading(false);
    }
  };

  const handleInnovationStatusChange = async (id: string, status: string) => {
    setIsLoading(true);
    try {
        const updatedData = await updateInnovationStatus(id, status);
        setData(updatedData);
    } catch(e) {
        alert("Erro ao atualizar status.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleInnovationDelete = async (id: string) => {
    if (!window.confirm("Tem certeza que deseja excluir esta inovação?")) return;
    setIsLoading(true);
    try {
      const updatedData = await deleteInnovation(id);
      setData(updatedData);
    } catch (e) {
      alert("Erro ao excluir inovação.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('tracker');
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
    <button
      onClick={() => {
        setActiveTab(id);
        setIsMobileMenuOpen(false);
      }}
      className={`flex items-center w-full px-6 py-4 text-left transition-colors border-r-4 ${
        activeTab === id 
          ? 'bg-slate-800 border-blue-500 text-blue-400 font-medium' 
          : 'border-transparent text-slate-400 hover:bg-slate-800 hover:text-slate-200'
      }`}
    >
      <Icon className={`w-5 h-5 mr-3 ${activeTab === id ? 'text-blue-400' : 'text-slate-500'}`} />
      {label}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar for Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 border-r border-slate-800 fixed h-full z-10 text-white shadow-xl">
        <div className="p-6 border-b border-slate-800">
          <div className="mb-6 flex items-center gap-3">
             <img 
               src={COMPANY_LOGO_URL}
               alt="Logo" 
               className="h-10 w-auto max-w-[50px] object-contain" 
             />
             <div className="flex flex-col">
                <span className="text-2xl font-bold text-white leading-none tracking-tight">
                  Project<span className="text-blue-500">Tracker</span>
                </span>
             </div>
          </div>

          <div className="flex items-center text-slate-500 text-xs mb-1 uppercase tracking-wider font-semibold">
            Painel de Controle
          </div>
          <p className="text-sm font-medium text-slate-200 truncate">{currentUser.name}</p>
          <div className="flex items-center mt-2 gap-2">
            <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400 bg-slate-800 border border-slate-700 px-2 py-0.5 rounded-full inline-block">
                {currentUser.role}
            </span>
          </div>
        </div>
        <nav className="flex-1 mt-6 overflow-y-auto">
          {['PROJETISTA', 'GESTOR'].includes(currentUser.role) && (
             <NavItem id="tracker" label="Projetar" icon={PenTool} />
          )}

          {canSeeAllHistory && (
             <NavItem id="history" label="Histórico" icon={History} />
          )}

          <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />

          <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />

          {canSeeInnovations && (
             <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
          )}

          {currentUser.role === 'GESTOR' && (
            <NavItem id="team" label="Gestão de Equipe" icon={Users} />
          )}
        </nav>
        <div className="p-6 border-t border-slate-800 bg-slate-900">
          <button 
            onClick={handleLogout}
            className="flex items-center text-sm text-red-400 hover:text-red-300 hover:bg-slate-800/50 p-2 rounded-lg font-medium transition-colors w-full"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Sair da Conta
          </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full bg-slate-900 border-b border-slate-800 z-20 flex justify-between items-center p-4 shadow-md">
        <div className="h-8 flex items-center gap-2">
            <img 
                src={COMPANY_LOGO_URL} 
                alt="Logo" 
                className="h-full w-auto object-contain"
            />
            <span className="text-lg font-bold text-white">
                Project<span className="text-blue-500">Tracker</span>
            </span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-slate-300 hover:text-white transition-colors">
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-900 z-10 pt-20 md:hidden animate-in slide-in-from-right duration-200">
          <nav className="flex flex-col h-full overflow-y-auto">
            {['PROJETISTA', 'GESTOR'].includes(currentUser.role) && (
                <NavItem id="tracker" label="Projetar" icon={PenTool} />
            )}
             {canSeeAllHistory && (
                 <NavItem id="history" label="Histórico" icon={History} />
            )}
            <NavItem id="dashboard" label="Painel & Gráficos" icon={LayoutDashboard} />
            <NavItem id="issues" label="Qualidade" icon={AlertOctagon} />
            {canSeeInnovations && (
                <NavItem id="innovations" label="Inovações & Custos" icon={Lightbulb} />
            )}
            {currentUser.role === 'GESTOR' && (
               <NavItem id="team" label="Gestão de Equipe" icon={Users} />
            )}
            <div className="mt-auto p-6 border-t border-slate-800">
              <button 
                onClick={handleLogout}
                className="flex items-center w-full px-4 py-3 text-left text-red-400 hover:bg-slate-800 rounded-lg transition-colors"
              >
                <LogOut className="w-5 h-5 mr-3" />
                Sair
              </button>
            </div>
          </nav>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-6 pt-24 md:pt-6 transition-all bg-gray-50 min-h-screen">
        {isLoading && (
          <div className="fixed top-0 left-0 w-full h-1 bg-blue-100 z-50">
            <div className="h-full bg-blue-600 animate-pulse w-full"></div>
          </div>
        )}
        <div className="max-w-5xl mx-auto">
          {/* Tracker Tab */}
          <div className={activeTab === 'tracker' ? 'block space-y-6' : 'hidden'}>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Área de Projeto</h2>
                <p className="text-gray-500">Bem-vindo, <span className="font-semibold text-blue-600">{currentUser.name}</span></p>
              </div>
            </div>
            <ProjectTracker 
              existingProjects={displayData.projects}
              onCreate={handleProjectCreate}
              onUpdate={handleProjectUpdate}
              isVisible={activeTab === 'tracker'}
              onNavigateBack={() => setActiveTab('tracker')}
            />
          </div>

          {activeTab === 'history' && (
